module.exports = {
  "1": { "n": "小灵面", "e": 14, "r": 1, "d": "面具似乎可以摘下，进食的时候会避开所有生物。一层闪着荧光的神秘物质覆盖着身体，内部可能是液体。" },
  "2": { "n": "蒲公英", "e": 1, "r": 1, "d": "喜欢阳光，可爱的圆形精灵，三只一起在草丛中随风飘动。风吹到哪就会飞到哪，总是无忧无虑的。" },
  "3": { "n": "旋叶虫", "e": 0, "r": 1, "d": "" },
  "4": { "n": "逗逗", "e": 13, "r": 1, "d": "体内充满轻质气体，骨骼与肌肉结构都很轻，因此可以在空中漂浮活动。它通过换气调节气体量与分布，来控制自己上浮或下沉。" },
  "5": { "n": "菇菇丁", "e": 5, "r": 1, "d": "“你知道吗？菇菇丁早已建立了广阔的地下王国，它们的菌丝体蔓延到整片森林，链接着许多土壤，将沾染了星星魔法碎屑的砂土和木头转化为魔法力量，循环利用，它们才是这片森林的主人！”" },
  "6": { "n": "豆丁鱼", "e": 3, "r": 1, "d": "总是抿着嘴巴气鼓鼓的样子，实际上不是因为生气了，而是在努力练习游泳，传说它们一族有着龙的血脉，只要努力游泳就可以进化为龙，基于精灵遗传学理论推测是龙系混血的精灵。" },
  "7": { "n": "小鹬", "e": 12, "r": 1, "d": "小鹬有着灰白色的羽毛，孱弱的双翼还无法驾驭风的力量，但可以依靠尚为柔软的皮甲结构进行短暂的滑翔。虽然幼小却已经懂得在划过水面时溅起水花，吸引鱼虾露头，有时能收获比自己体型还大的战利品。" },
  "8": { "n": "地鼠", "e": 0, "r": 1, "d": "" },
  "9": { "n": "哭哭菇", "e": 17, "r": 1, "d": "成群地栖息在潮湿少光的地域，分泌出来的粘液具有独特的气味，引诱旅人深入密林，吸入过多这种气体便会不停流泪。" },
  "10": { "n": "小草虫", "e": 10, "r": 1, "d": "果树分叉越多的地方，越容易找到他们，常常被误认为是未熟的青葡萄。肤表黏糊糊的，睡觉时缩成一团挂在树上。常观察到许多只挤在一起，目前推测是畏寒的原因。" },
  "11": { "n": "闪电环", "e": 0, "r": 1, "d": "总是一副不开心的样子，面对对手的时候会使出全力攻击，不论所处环境有多么危险，只要没电就会立刻陷入昏睡。" },
  "12": { "n": "螺旋帕帕", "e": 16, "r": 1, "d": "它们立志成为机械系精灵维修专员，曾有大批战损的机械系精灵奇迹般地恢复健康，排着队回到原来生活的地方，这背后默默付出的正是不起眼的螺旋帕帕。" },
  "13": { "n": "公平鸽", "e": 0, "r": 3, "d": "第一、绝对不放过任何争执！第二、绝对不能因为睡过头晚到现场！第三、绝对要公正裁判！第四、绝对要在被双方驱逐之前做出判决。——《公平鸽的守则》" },
  "14": { "n": "花怨鳗", "e": 5, "r": 1, "d": "它们的身体有趋触性，身躯底部会紧贴赖以生存的土地，这让它们有安全感，尤其喜欢湿润的泥土。三朵花常相互缠绕以保持接触，但也因此容易打结。当它们争执时，会发出连绵的铃声。" },
  "15": { "n": "刺轮砣", "e": 0, "r": 1, "d": "" },
  "16": { "n": "伊贝尔", "e": 0, "r": 1, "d": "" },
  "17": { "n": "毛毛", "e": 10, "r": 1, "d": "喜欢藏在地下，靠形似耳朵的触角感知周围环境。几乎观察不到它们进食行为，吃很少的东西就能存活很久。" },
  "18": { "n": "海枝枝", "e": 0, "r": 1, "d": "" },
  "19": { "n": "恶魔叮", "e": 15, "r": 1, "d": "身体里似乎装满了坏心思，很轻松就能从试图抓住它的洛克手中挣脱。会三五成群地从洛克手上抢走东西，把东西丢下之后嘻嘻哈哈地飞走。如果惹怒它们的话，会气呼呼地撞向洛克。" },
  "20": { "n": "绿翼鸟", "e": 13, "r": 1, "d": "胆小谨慎的精灵，总是下意识地遮挡和隐藏自己。头部心型冠的原理不明，要小心对待，拉扯后，绿翼鸟的性格和样貌会大变，拉扯三次后变回本来的性格和样貌。" },
  "21": { "n": "优优", "e": 5, "r": 1, "d": "白天，它们竖起蓬松的尾巴，在沙地上蹦跳活动。夜里守在洞口放哨，尾尖亮起柔和的暖黄光，并用尾巴轻点地面，把消息无声地传给同伴。" },
  "22": { "n": "小电企鹅", "e": 6, "r": 1, "d": "它们生活在寒冷的水域，会用头顶的晶体吸收空气里的电能量。当能量充足时，晶体表面会浮现细碎的亮纹和电光。偏爱暴雪与打雷的天气，风雪越大、雷声越近，它们越活跃。" },
  "23": { "n": "号儿鱼", "e": 3, "r": 1, "d": "拥有中空结构的尾巴，空气和水流过的时候会发出小号一样响亮的声音。非常喜欢社交的生物，经常举办盛大的音乐会，不同的小号精灵会轮流展示自己的音乐才华，创造出令人惊叹的合奏。" },
  "24": { "n": "格兰种子", "e": 1, "r": 1, "d": "格兰种子可以借助微风悬于空中。总是呆呆地望着对方，其实脑袋里盘算着许多鬼点子。体内花粉不停生长，使它躁动不安，总是忍不住捉弄其他精灵。" },
  "25": { "n": "小黑猫", "e": 0, "r": 1, "d": "在白天，小黑猫们经常闭眼休息，揣着手休息，如果冒昧地扒开它们的眼皮，会发现很多时候并没有在睡觉，有一种说法：小黑猫闭眼就是在思考。" },
  "26": { "n": "果冻", "e": 3, "r": 1, "d": "透明而不起眼的精灵，经常在干净的水源被发现。研究发现，果冻精灵可以维护森林、湖泊和山脉的生态平衡，似乎是因为它们能让水变得清澈。" },
  "27": { "n": "一窝蜂", "e": 10, "r": 1, "d": "悬浮着的蜂巢就像身体的一部分一样灵活运动。可能是受某种信息素或者魔法影响，总会默契地做出协同的动作。" },
  "28": { "n": "小夜", "e": 15, "r": 1, "d": "身手敏捷的小猫，擅长在雾气中隐藏身形，也可以幻化成其他物体。常常以惊讶和恐惧为食，消化后会散发出一种奇怪的味道。" },
  "29": { "n": "奇丽草", "e": 1, "r": 1, "d": "头顶着花苞爬着前进，总会朝着太阳光的方向。花苞里面似乎孕育着什么，要是长期照不到太阳，花苞就会萎缩。" },
  "30": { "n": "乖乖鹊", "e": 0, "r": 1, "d": "" },
  "31": { "n": "可立鸡", "e": 2, "r": 1, "d": "鸡冠有特殊腺体分泌可燃气体，情绪激动时，鸡冠会熊熊燃烧。为了便于警戒，可立鸡会排成一队，由鸡冠火焰最旺盛的个体来带领。" },
  "32": { "n": "蹦蹦种子", "e": 0, "r": 1, "d": "" },
  "33": { "n": "斑斑", "e": 12, "r": 1, "d": "和噜噜家族是远亲，但几乎从不联系，即使是同种族的斑斑们互相之间也并不亲近。从蛋里孵出来之后就非常独立了，经常迈着毛茸茸的小腿，挥着小小的翅膀巡视领地，十分高傲。" },
  "34": { "n": "菊花梨", "e": 13, "r": 3, "d": "看起来像梨，闻起来像梨，尝起来味道也像梨。睡觉的时候会把身体藏在泥巴里，只把花朵留在地面上。小黄蜂想要来授粉的话它会非常苦恼。" },
  "35": { "n": "奔波鼠", "e": 5, "r": 1, "d": "毛色杂乱且粗糙，像是融合了泥土、枯叶的颜色，黑色的眼睛透露出机灵的光。它们背着自己的全部家当，在野外长期流浪，一直在路上，从未到达旅途的终点。有着健壮的身躯，但进攻意愿低，只对闪闪发光的东西兴趣浓厚。" },
  "36": { "n": "乌达", "e": 0, "r": 1, "d": "" },
  "37": { "n": "绿耳松鼠", "e": 0, "r": 1, "d": "能靠有力的尾巴弹跳，如果摔倒了，要花一阵子才能重新靠尾巴站立，有研究猜测它们足部功能有所退化，尾部功能非常发达，部分取代了双脚的作用。" },
  "38": { "n": "兽花蕾", "e": 4, "r": 3, "d": "稀兽花种的幼年形态，非常轻，会随风而动，身后有像翅膀一样的苞片，苞片上有特殊的薄膜，可以起到防风防水的效果，保护它们健康成长。" },
  "39": { "n": "丢丢", "e": 0, "r": 1, "d": "" },
  "40": { "n": "波波螺", "e": 5, "r": 1, "d": "经常频繁抖动身体，推测是缓解外壳生长带来的不适感。它们常集体排成一列迎向海浪，借助外壳的结构消解冲击。浪头拍来时会张口吸入送上门的食物，连很硬的东西也能消化。" },
  "41": { "n": "草头鸭", "e": 1, "r": 1, "d": "眼睛长在两侧，不停地转动，不知道是不是在思考，很难解读它的行为规律。视觉范围有360度，从任何方向接近都会被它发现。" },
  "42": { "n": "呆小路", "e": 1, "r": 1, "d": "幼年期较长，主要靠嗅闻、聆听和头上的叶子触角获取信息。头顶毛发会散发出爆米花的香味，偶尔引来其他精灵。它们之间用互闻头顶代表问候。" },
  "43": { "n": "小箱怪", "e": 16, "r": 1, "d": "被当作具有自我意识的宝箱，又因为与宝箱形似，变成了象征宝箱的吉祥物精灵。有些洛克会对着小箱怪祈祷好运，甚至向它投掷洛克贝许愿。" },
  "44": { "n": "矿石石", "e": 5, "r": 1, "d": "古老的种族，似乎和现在的精灵们很少交流，但对洛克族十分友好。地系部族掌握建造之术后的创造的第一个物种。在古代也被用作计量单位，一个石石约等于三十千克。" },
  "45": { "n": "多西", "e": 16, "r": 1, "d": "可以通过磁性来悬浮在空中，对影响磁场稳定的东西异常敏感，偶尔会因为磁力吸来一些莫名其妙的小零件。可以通过操纵磁力来造成巨大的破坏，常是电力故障的罪魁祸首。" },
  "46": { "n": "呼呼猪", "e": 6, "r": 1, "d": "得益于能够分泌疏水性油脂的皮脂腺，皮毛紧实而油亮，既防水又防寒。四肢短而粗壮，跑起来很快，奔跑时偶尔轻微摆动尾巴用来保持平衡。" },
  "47": { "n": "雪娃娃", "e": 6, "r": 1, "d": "它对洛克族异常友好，面对温暖的抚摸和拥抱也从不抗拒。传说它们是最早与洛克建立契约的种族之一，耳朵的轮廓正像星之链在契约双方之间勾勒出的形状。" },
  "48": { "n": "小鼠獭", "e": 0, "r": 1, "d": "总是在啃着什么，包括自己的手和尾巴。扒开小鼠獭的嘴巴仔细观察也找不到牙，牙床嫩嫩的，还没有牙的痕迹。" },
  "49": { "n": "古钟蛇", "e": 13, "r": 1, "d": "通常低伏身体，隐藏在草丛中，只露出尾巴发出咚咚咚的轻响，吸引好奇的精灵过来。其尾部的结构可以在摇晃时发出咚咚的鼓声，据说玄玉岛的洛克以此为灵感，制作出了某种广受欢迎的玩具。" },
  "50": { "n": "小甲虫", "e": 10, "r": 1, "d": "头盔顶部和双手上都有黄色的尖角，锋利而坚硬。听说在它们的世界里，坚硬且粗壮的角是身份地位的象征。" },
  "51": { "n": "海盗虫", "e": 0, "r": 1, "d": "" },
  "52": { "n": "板板壳", "e": 3, "r": 1, "d": "平时看似懒懒的，感到危险时，柔软的身体会迅速缩回壳里。柔韧的尾巴看起来像海草，偶尔会被饥饿的水生精灵咬一口。" },
  "53": { "n": "灵狐", "e": 2, "r": 1, "d": "鼻子呼出的热热的气可能会灼伤小洛克的手，如果在雪山不小心被冻伤，去拜托灵狐帮忙吹一口热气，冻伤瞬间就会痊愈了。" },
  "54": { "n": "电咩咩", "e": 0, "r": 1, "d": "整个咩咩非常蓬松，每一根蓬松的毛都带电，稍微靠近它就要被静电“哔哩”一下。释放能量之后会进入低电量状态，低电量时会没精打采并吃很多。" },
  "55": { "n": "拉特", "e": 0, "r": 1, "d": "同伴之间经常会打架，用头或者用拳头对撞。每撞一下都会闪着电光。大多数拉特沉默寡言，但正义感十足，拉特们会出手帮助遇到麻烦的洛克和精灵。" },
  "56": { "n": "甜田螺", "e": 3, "r": 1, "d": "它们进食较少，通过经常睡觉来维持体内养分的平衡。只有在海水退潮时才偶尔会出现在沙滩上，在醒着的时候才会立起来，每天大概只有五分之一的时间是醒着的。" },
  "57": { "n": "吸泥鸥", "e": 5, "r": 1, "d": "骨骼天生比较脆，需要经常吸食淤泥，泥巴里面含有它们骨骼所需的物质。如果摄入不足，它们的关节会发炎，走起路来可能容易摔倒。吻部尚未完全发育，偶尔会被泥巴噎住。" },
  "58": { "n": "雪豆丁", "e": 6, "r": 1, "d": "出生后被父母放置在雪窝里，进食补充的能量会在冬眠时令身躯快速成长。大手大脚的雪豆丁习惯于翻滚着移动。思维直接，比较容易发脾气，可以抚摸脑袋令其冷静。" },
  "59": { "n": "机械方方", "e": 16, "r": 1, "d": "似乎是一种非常古老的机械系造物，用处不详。身体结构精巧，拨弄它头顶的天线，会让它变得十分愉快，甚至能断断续续地播放音乐。“方方正正，顶天立地，做人亦该如此。\"" },
  "60": { "n": "小狮鹫", "e": 0, "r": 1, "d": "" },
  "61": { "n": "治愈兔", "e": 2, "r": 1, "d": "平时生活在灌木丛中，看到洛克的话会因为好奇而主动靠近。据说如果感冒了的小洛克摸摸它的小脚，就会很快康复。" },
  "62": { "n": "棋棋", "e": 11, "r": 1, "d": "“黄金时代地系部族大多无法运用魔力，但他们有着独特的智慧和精湛的技艺。地系精灵王教他们使用建造之术，地系部族用黑色矿物做出了棋子精灵，用以娱乐。”——《黄金时代的地系工匠们·二》" },
  "63": { "n": "护主犬", "e": 2, "r": 1, "d": "时刻保持着警觉，任何危险都无法逃过他的眼睛。虽然身形小巧，但面对无论多么凶猛庞大的敌人都会勇敢地燃起斗志。" },
  "64": { "n": "锥尾羊", "e": 14, "r": 1, "d": "白色的毛十分蓬松，脚掌柔软，移动时悄无声息，因此很擅长藏身草原与坡地。它性格安静，同类之间常用轻轻顶犄角的方式交流。" },
  "65": { "n": "鸭吉吉", "e": 0, "r": 3, "d": "它的眼皮开始打架，脑袋一点一点前倾——虽然随时能睡，但是也随时能醒。当你以为它睡着了，它能猛地抖翅，把自己从瞌睡里吓醒，大喊“嘎噶——！”" },
  "66": { "n": "多多", "e": 9, "r": 1, "d": "头部帽子一样的组织触感舒适，冰凉弹软。受到惊吓的话，会从头部喷射出大量毒液，之后迅速缩起陷入昏厥状态。" },
  "67": { "n": "风铃鲨", "e": 3, "r": 1, "d": "如果看见它们在水面上大量聚集，往往预示着快要下雨。它们的尾巴摆动时带起细小涟漪，薄膜边缘会在气流中轻轻振动，发出清亮悦耳的声响。" },
  "68": { "n": "胆小鳗鱼", "e": 0, "r": 1, "d": "以强力放电而闻名的精灵，种族中的鳗鱼们似乎对自己的知名度一无所知。常常畏首畏尾，即使是非常弱小的对手，也能令它们战战兢兢。曾有胆小鳗鱼假死晕倒在浅滩上，原因是一只爬爬路过。" },
  "69": { "n": "小怂猫", "e": 11, "r": 1, "d": "胆量极小的猫科精灵，曾因极少被观测记录，被王国记录为已灭绝的物种。翼膜上的眼状图案可以吓退大多数天敌，遇到敌人会张开双臂一动不动地站着，一直到对方离开或者自己昏厥。" },
  "70": { "n": "白发懒人", "e": 0, "r": 1, "d": "一直闭着眼睛在睡觉，即使是醒了也看不出来。在它睡着的时候也能对听到的声音有所反应，仿佛是个熟练的梦游者。" },
  "71": { "n": "布是石", "e": 5, "r": 1, "d": "如果感觉岩石的缝隙中有目光注视着你，那很可能就是布是石。身体非常坚硬，喜欢成群结队地斜坡上滚下来，也许只有它们能感受这种快乐吧。" },
  "72": { "n": "火尾瓦特", "e": 2, "r": 1, "d": "全身被毛又干燥又粗糙，容易产生静电现象，甚至偶尔冒出火星。它的利爪有可能是打火石，连续抓挠树木的话可能会将树木点燃。" },
  "73": { "n": "石肤蜥", "e": 5, "r": 1, "d": "常在半山腰处被发现，独立生活，会收集细小的石头筑巢。背上的石头是体内生长出来的一种分泌物，喜欢钻到石头堆里蹭背，可以把背上的石头打磨得更加锋利。" },
  "74": { "n": "大头骨龙", "e": 7, "r": 1, "d": "首次被人发现时，大头古龙在地下岩层中沉睡，并且对现在的世界和精灵社会一无所知。骨架不仅坚硬，而且具有再生能力。即使骨头被打断，也可以在短时间内重新长出。骨质翅膀虽然看起来脆弱，但实际上非常坚韧。" },
  "75": { "n": "伊雷龙", "e": 7, "r": 1, "d": "幼年的小龙喜欢在雨天调皮捣蛋，充满水分的环境令它们十分活跃，在水里游得飞快，小洛克抓也抓不住它们。" },
  "76": { "n": "小星光", "e": 0, "r": 1, "d": "" },
  "77": { "n": "权杖-II", "e": 0, "r": 1, "d": "" },
  "78": { "n": "幽影树", "e": 14, "r": 3, "d": "左手和右手似乎有独自的想法，在黑暗中看起来就像三只精灵。虽然伪装拙劣到谁都能看穿的程度，但依旧喜欢伪装成普通树木的样子，跟在洛克身后，但是对洛克并没有恶意。" },
  "79": { "n": "水母", "e": 3, "r": 1, "d": "柔软的精灵，通过收缩身体喷水在水中前进。会使用触手释放毒素，以此麻痹对手，然后将其拖入水中。" },
  "80": { "n": "电动长颈鹿", "e": 0, "r": 1, "d": "平时几乎不带电，通过尾巴放电，贸然摸尾巴可能会被电晕。听到节拍时，它体表的细微电感会跟着节奏一跳一跳，像在悄悄打拍子。" },
  "81": { "n": "提塔", "e": 0, "r": 1, "d": "" },
  "82": { "n": "小独角兽", "e": 4, "r": 1, "d": "漂亮柔软的绿色鬃毛，让谁看了都想抚摸一下。不知是不是它散发出的魔力的缘故，在它的身边会感觉心灵也变得纯净了。" },
  "83": { "n": "里拉鳐", "e": 3, "r": 3, "d": "里拉鳐的体表能够分泌并牵连出细长的粘液，这些粘液对水流变化极其敏感，能帮助它判断水流方向。游动时，水流掠过粘液弦会引发持续振动，发出琴音。一般认为雄性的气孔粘液更少，形成的琴弦更细，因此琴声更清脆明亮。" },
  "84": { "n": "阿米亚特", "e": 5, "r": 1, "d": "全身都是岩石，但是眼睛周围没有岩石保护，是十分脆弱的柔软皮肤。喜欢吃不同口味的矿石，总是静静呆着，没什么存在感。" },
  "85": { "n": "嘟嘟煲", "e": 9, "r": 1, "d": "体内的粘液有毒性，总是黏糊糊的，一旦沾上很难洗掉，粘液的沸点十分低，常处于沸腾状态。" },
  "86": { "n": "锤头鹳", "e": 12, "r": 3, "d": "三三两两地站在建筑的高处，有些神秘，被认为是王国的守护者。洛克靠近时，会发出尖锐刺耳的声音，头部奇怪的形状为工具设计提供了设计灵感。" },
  "87": { "n": "石石", "e": 5, "r": 1, "d": "古老的种族，似乎和现在的精灵们很少交流，但对洛克族十分友好。地系部族掌握建造之术后的创造的第一个物种。在古代也被用作计量单位，一个石石约等于三十千克。" },
  "88": { "n": "海豹战士", "e": 11, "r": 1, "d": "圆润的身躯游得飞快，皮肤非常滑溜，十次抓捕中九次都要被它溜走。喜欢被紧挨着或被挤压着的感觉，经常成群结队地出没，迷路的时候，也会一整群一起迷路。" },
  "89": { "n": "恶魔狼", "e": 15, "r": 3, "d": "胸前的毛发非常粗糙，似乎能够起到保护作用。能够在战场上高速地移动，迅猛的前爪攻击十分有力。" },
  "90": { "n": "记忆石", "e": 5, "r": 3, "d": "埋在土地里露出上半截，就像是石碑一样。通过扫描分析它所散发的波动，能窥见一点点王国百年前的历史。" },
  "91": { "n": "奔乐鹿", "e": 8, "r": 2, "d": "非常喜欢被抚摸，但要避开头、脚和尾巴。夜间视力很差，通常会睡眠；若必须夜间行动，会消耗能量点亮头顶电球来照明，而电球的明暗也会随听见的节拍起伏。" },
  "92": { "n": "抱枕松鼠", "e": 0, "r": 2, "d": "骑着自己的尾巴，已经不需要靠双脚走路。偶尔把头埋进身体，看上去像一颗巨大的果实。" },
  "93": { "n": "斑枭", "e": 12, "r": 3, "d": "和洛克相交甚少的种族，拥有比较强的野性和攻击性。如果在领地内看到生面孔，可能俯冲下来攻击对方，拥有出色的深度感知能力和夜视能力，即使藏在阴影处也难以逃过它的双眼。" },
  "94": { "n": "爆焰仔", "e": 2, "r": 1, "d": "借助风来移动的精灵，碰到水的时候会停下来休息。" },
  "95": { "n": "爆焰喷喷", "e": 2, "r": 2, "d": "借助风来移动的精灵，碰到水的时候会停下来休息。" },
  "96": { "n": "爆角龙", "e": 5, "r": 1, "d": "" },
  "97": { "n": "白发路路", "e": 1, "r": 3, "d": "白色的毛发覆盖手臂和身体，随身携带的蛋散发出爆米花的香味。能从随身携带的蛋中获得勇气和力量，暂时还不清楚是什么原理。" },
  "98": { "n": "白金独角兽", "e": 4, "r": 3, "d": "在黑暗中能够照亮周围，像神明一般圣洁而华丽。头顶的角除了穿刺敌人，还能施放出让人震撼的强大魔法冲击。" },
  "99": { "n": "矮脚爬爬", "e": 10, "r": 1, "d": "足较短，翻倒后很难再顺利站起来。野外发现的矮脚爬爬里面十个有八个正在努力翻身。因为可爱的外表而受到许多小洛克的喜爱，但受惊时会咬人，致使王国只能贴出告示，警告大家不要轻易触碰。" },
  "100": { "n": "贝加尔", "e": 16, "r": 2, "d": "身体结构十分精巧，能够最高效地利用能源，是某些发热供暖装置的设计原型。但在氧气不足的地方身体会逐渐冷下来进入睡眠状态。“经过了岁月的磨练和沉淀，透露出时光的浑厚。”" },
  "101": { "n": "贝古斯", "e": 16, "r": 3, "d": "能够通过头顶的蒸汽猜出贝古斯的心情，对于它们而言，不同的心情需要消耗不同数量的矿石。“它是安静的，像座山一样，守候在这里，亘古不变，然而它又是有生命的，内心之中迸发出无限的生机。”" },
  "102": { "n": "贝瑟", "e": 16, "r": 1, "d": "拥有坚硬而沉重的外壳，靠石头和木头补充提供能量，在能量短缺的时候会靠睡觉度过。“它是坚硬的，它永远不会破碎。可当你狠心地对待它，它终究会伤心地沉睡。”" },
  "103": { "n": "蹦蹦果", "e": 1, "r": 3, "d": "手中的果实能将吸收的光能转化为能量，因此日照时间越长，果实积累的能量就越高。据野外观察记录，在日光、月光或特定魔法光环境下成熟的蹦蹦果，会呈现出明显不同的果香味道。" },
  "104": { "n": "阿布", "e": 0, "r": 1, "d": "虽然长着小巧而可爱的翅膀，但是不用来煽动飞行,完全是凭借自身的魔法浮空，似乎能与洛克心灵相通。" },
  "105": { "n": "阿米樱", "e": 5, "r": 2, "d": "石头组成的上身和双臂异常粗壮，腿部短小，经常会腿痛。重重挥拳的时候会把构成手部的石头都打散，不过很快就会用岩石修补好。" },
  "106": { "n": "不咕钟", "e": 16, "r": 1, "d": "曾因机械禁令被大量屠杀，现在数量稀少，也更加胆小，求生本能让它们逃跑速度极快，遇到危险时，它们会加速或减慢时钟指针的转动从而短暂地影响到局部时间的流逝。和黄金时代遗留下来的精灵关系良好，会寻求其庇护。" },
  "107": { "n": "兵螂", "e": 10, "r": 2, "d": "前肢能够对三倍体型大小的昆虫精灵造成重创，食量极大。似乎是通过液压结构控制节肢和口器，弹出的速度极快，肉眼很难看清楚。需要吃大量食物来维持节肢力量。" },
  "108": { "n": "冰封怨灵", "e": 6, "r": 2, "d": "缔结契约的向往更明显，甚至会主动靠近潜在契约者，似乎由冰元素和某种尚不清楚的物质构成，推测这部分来自强烈的信念和精神力，使它们的契约更稳定、也更难被外力改变。" },
  "109": { "n": "冰晶虎", "e": 6, "r": 2, "d": "" },
  "110": { "n": "冰虎宝", "e": 6, "r": 1, "d": "" },
  "111": { "n": "冰钻布鲁斯", "e": 6, "r": 3, "d": "会拾取断落的枝桠，并在枝桠表面上喷覆与头部成分相似的晶体化物质，使其变得坚硬冰冷，作为武器使用。" },
  "112": { "n": "布克棱岩", "e": 5, "r": 3, "d": "颇具威慑力的精灵，身形巨大，不经常远离驻地。看上去很重，但其实身体的主要重量都集中在头和手上的岩石部分。" },
  "113": { "n": "布是岩", "e": 5, "r": 2, "d": "脑袋部分的坚硬度接近基岩，普通的岩石对它来说就像泥土一样柔软。它的头好像完全感觉不到疼，受到击打很久之后才能明白刚才发生了什么。" },
  "114": { "n": "布瓜蝌", "e": 17, "r": 1, "d": "" },
  "115": { "n": "布鲁斯", "e": 6, "r": 1, "d": "头部开始晶体化，触感冰凉。能缓慢吸收周围热量，使自身温度维持在较低水平。头顶的白色绒球对温度变化很敏锐，能帮助它判断环境冷热。" },
  "116": { "n": "怖哭菇", "e": 17, "r": 3, "d": "长期在暗处生存，双目视觉逐渐退化，演化出了胸前能够探测、储存幻系能量的触手。幻系能量凝聚在菌柄中，赋予了其极强的再生能力，即便是经过火焰的炙烤，依旧能迅速生出饱满的躯体。" },
  "117": { "n": "怖须菇", "e": 17, "r": 2, "d": "会将身体埋入土壤中，依靠独特的腺体将吸收的水分转化为带有毒性的黏液，干燥与炎热时，散发的气味微微发酸，闻到会想起悲伤的事情。" },
  "118": { "n": "捕尘长绒", "e": 10, "r": 3, "d": "绒毛长而纤细，每个洛克小时候都曾把家里打扫清洁的捕尘长绒当作魔法扫帚骑着玩，然后被家长揍一顿，而家长顺手拿起的武器也是捕尘长绒，但是它们喜欢被洛克需要。" },
  "119": { "n": "波多西", "e": 16, "r": 3, "d": "能将钢铁之力积蓄于双爪中，使出蓄力重击，威力十足。以地底的粗矿为食，精炼过的钢铁对它而言似乎有着不同寻常的风味。在它出没的地方，常有铁锅失窃。" },
  "120": { "n": "波普鹿", "e": 8, "r": 3, "d": "每当它听见动感的旋律，体内电流便会随着节奏起伏变化，头顶电球忽闪忽闪照亮回家的路。波普鹿用尾巴打出轻缓的节拍，是它在表达愉快的心情。" },
  "121": { "n": "波波拉", "e": 3, "r": 2, "d": "在水中自如地游动，头上的触角可以感受水中的变化，总是带着一颗球一样的东西。身旁环绕着特殊的水元素，水元素凝结体中蕴含魔法能量的波动。" },
  "122": { "n": "蹦床松鼠", "e": 0, "r": 3, "d": "尾巴的力量非常强，巨大的尾部并不是蓬松的，内部有着强健的肌肉，实心并且富有弹性。可以用尾巴把自己弹射到三层楼那么高的地方。" },
  "123": { "n": "鄙目鹬", "e": 12, "r": 2, "d": "栖息在水边的浅滩，橘色的长脚使得它们非常适合涉水行走，喜欢捕食昆虫和甲壳类动物，其眼神如同寒星般锐利冷峻，会左右轻轻扇动翅膀，溅起阵阵涟漪，模仿弱小生物游动，吸引鱼类前来。" },
  "124": { "n": "刺电环", "e": 8, "r": 2, "d": "经常三三两两聚集在一起互相充电。情绪也会随着电力在同伴之间传播，群聚在一起容易变得更不开心，靠近后能听到此起彼伏的电流杂音，偶尔还有“呜呜”的声音。" },
  "125": { "n": "刺盔虫", "e": 3, "r": 2, "d": "刺上会卡着贝壳，木片，海藻。长长的棘刺有大量感光细胞，对光线非常敏感，具有负趋光性，为了逃避光线会在日间抓着各种东西为自己遮挡光线。食物充足时移动距离也会稍微变大。" },
  "126": { "n": "大耳帽兜", "e": 6, "r": 1, "d": "全身覆满白色绒毛，能抵御寒冷，仔细观察它们的毛毛分为两种，一种是顺滑纤细的针毛，另一种是又软又密的绒毛。虽然体型小，但却不畏惧寒冷，小小的手爪柔软又温暖。似乎喜欢抱抱。" },
  "127": { "n": "彩虹独角兽", "e": 4, "r": 3, "d": "彩虹独角兽的毛发可以随环境光线改变反射的波长，在不同角度呈现彩虹般的绚丽色彩。它也是精灵种群中最为了解洛克的存在，友谊的力量会在彼此心中唤醒新的希望。" },
  "128": { "n": "彩蝶鲨", "e": 3, "r": 3, "d": "常被目击从水面贴风飞过，轻盈得几乎不留波纹，它飞行时会借气流而动，并且发出清亮的声音。危险逼近时，它会迅速褪淡体色，降低存在感，再沿风向逃跑。" },
  "129": { "n": "春兔", "e": 1, "r": 2, "d": "耳朵的皮肤呈透明玻璃状，触感柔软，内部可以储藏更多的露水。总是细心地做着准备，可以把自己和身边的同伴都照顾得很好，经常用手中的四叶草为其他精灵同伴遮雨。" },
  "130": { "n": "春团", "e": 1, "r": 1, "d": "春天草原上出生的小兔，成群出现，以露水为食。吸收的露水储存在耳囊中，因此散发出浆果和青草的香味。" },
  "131": { "n": "春花兔", "e": 1, "r": 3, "d": "即使找不到水源，也可以吸收耳朵里储存的大量露水。手中的四叶草变为双枪，能够汲取自然中逸散的草系能量，也能作为媒介释放魔法。经常帮助其他精灵，在某些地方被称为勇者兔兔。" },
  "132": { "n": "柴渣虫", "e": 2, "r": 1, "d": "“请避免在秋季携带柴渣虫进入山林，若因未采取防火措施而促成险情，洛克将承担所有责任。”——一则来自魔法部的公告" },
  "133": { "n": "炽心勇狮", "e": 2, "r": 3, "d": "是王国不休的守护者，它们拥有永不熄灭的火焰心脏，喷吐的火焰会越烧越烈。传说它曾以单狮之力击退山崩，火焰的温度能融化岩石。虽然性格高傲，但对认可的伙伴极为忠诚。" },
  "134": { "n": "炽热猿", "e": 2, "r": 2, "d": "会从头上喷出烟来彰显气势，普遍好斗。打喷嚏的时候，背上也会跟着喷出巨大的浓烟，还会洒出一些岩浆。" },
  "135": { "n": "炽焰狮", "e": 2, "r": 2, "d": "只是咆哮就能点燃空气，附着火系魔法的利爪能撕裂岩石。喉咙处的火囊发育成熟，可以喷吐高温火球，但偶尔会因能量过载而引发小型爆炸。" },
  "136": { "n": "翠顶夫人", "e": 12, "r": 3, "d": "柔弱温顺，羽毛软而蓬松。过于专注梳理羽毛可能会迷路，意识到迷路的时候通常已经游到了完全不认识的环境里。不过总能保持优雅淡定，似乎永远不会慌张惊恐。这或许是夫人为自己制定的礼仪规范。" },
  "137": { "n": "脆筒甜甜", "e": 6, "r": 1, "d": "使用淡奶油、蛋黄搅拌加热后，冷冻1000小时以上，有极小概率得到一只香草甜甜。以蛋筒底为支点蹦跶着前行，受到惊吓时会缩到自己的蛋筒里瑟瑟发抖。" },
  "138": { "n": "草衣虫", "e": 10, "r": 2, "d": "与果树是互利共生关系，在果树之间采蜜的同时完成授粉。尾部的花朵是虹吸式进食器官，能够用来吸取和储存花粉，是访花昆虫中最重要的种群。" },
  "139": { "n": "超能球球", "e": 17, "r": 1, "d": "主体是中心的球状陨石，其余均是由它操纵的石块，在它周围能检测到强烈的引力波动。力量几乎等同于一颗迷你行星，所幸大多个体性格温和，常被科学家们用作研究天体物理的对象。" },
  "140": { "n": "超能阿布", "e": 7, "r": 2, "d": "柔和的绒毛紧紧贴着线条流畅的身躯，优雅而有力的姿态令人安心。头顶的角能够放出魔力击退敌人，偶尔会以能量体的姿态跟随着洛克。" },
  "141": { "n": "齿轮小子", "e": 16, "r": 1, "d": "当齿轮小子遇到危险时，它会召唤种族里的其他齿轮小子，分别组成头部和身体，合体形成强大的机甲小子。" },
  "142": { "n": "冬羽雀", "e": 12, "r": 2, "d": "体型又小又圆，眼睛周围生长着一层柔软绒毛。羽绒非常厚，为了抵御寒冷的冬夜，常与同伴挤在一起栖息。" },
  "143": { "n": "动力猿", "e": 0, "r": 2, "d": "有一半的时间在睡觉，极少保持清醒，清醒时精力极其旺盛。会使劲捶打胸口努力让自己变得清醒，但是卖力地运动过后睡得更沉了。" },
  "144": { "n": "叮叮恶魔", "e": 15, "r": 3, "d": "一直在思考如何恶作剧，还会每天进行吓人的练习。总是歪嘴笑着，一副玩世不恭的样子，其实非常害怕失去别人的注意力。非常重视诺言，会坚定地完成自己的约定。" },
  "145": { "n": "呆火鸟", "e": 2, "r": 1, "d": "" },
  "146": { "n": "嘟嘟锅", "e": 9, "r": 3, "d": "一直在咕嘟咕嘟，分不清是因为沸腾导致，还是在喋喋不休。似乎有意四处散播谣言，说自己是炼金教室里大炼金釜的嫡系子嗣，研究人员在进行研究观测的时候每天要听五十遍它们讲的辉煌家史。" },
  "147": { "n": "大古拉海象", "e": 6, "r": 2, "d": "牙齿如冰晶一般剔透，凭借着锐利的海象牙，在海底甚至能与鲨鱼等顶级猎杀者一战。种群内的首领往往拥有最漂亮的鬃毛，虽然没有实质性的作用，但在海象群似乎是一种地位的象征。" },
  "148": { "n": "玳塔", "e": 17, "r": 1, "d": "" },
  "149": { "n": "玳龟", "e": 17, "r": 1, "d": "" },
  "150": { "n": "电企鹅", "e": 6, "r": 3, "d": "常成群扎堆出现来汲取更充沛的电能量，在寒冷区域居民的传说里，电企鹅大量聚集往往预示极端天气将至，当地还有个习俗——如果遇到雷暴天气，就把电企鹅放在房顶上，可以避免雷电损坏房屋。" },
  "151": { "n": "电球咩咩", "e": 8, "r": 3, "d": "头顶的毛团会定期脱落并瞬间萌发出新的一团。当遇到危险的时候，电球咩咩会快速脱落掉头顶毛团，以达到吸引敌人注意力的效果。" },
  "152": { "n": "蝶叶巨蜥", "e": 1, "r": 1, "d": "蝶叶巨蜥能鼓起脖颈周围皮肤褶皱使体型变大，像两片巨大的棕榈叶，它们能调整叶片的角度，可以改变风的流向，带来速度加成。遇到危险时，鼓起的巨大叶形褶皱还能威慑敌方。" },
  "153": { "n": "迪莫", "e": 4, "r": 3, "d": "这是关于勇气的故事，它很脆弱却也不曾退缩；这是关于梦想的故事，梦很简单却也执着。这就是我，迪莫。" },
  "154": { "n": "凡雀", "e": 12, "r": 1, "d": "" },
  "155": { "n": "凡鹰", "e": 12, "r": 3, "d": "" },
  "156": { "n": "多啦多", "e": 9, "r": 2, "d": "头部的粘液组织十分不稳定，情绪激动时甚至会掉落一部分。受到刺激后粘液会挥发到空气中，释放致幻毒素。" },
  "157": { "n": "多彩方方", "e": 16, "r": 2, "d": "似乎是一种非常古老的机械系造物，用处不详。热爱社交，尤其喜欢和其他种族的幼体玩耍。喜欢歌唱和舞蹈，但普遍不擅长舞蹈，容易摔倒。" },
  "158": { "n": "多灵", "e": 14, "r": 1, "d": "传说中灵魂的收集者，通过吸收其他精灵的灵魂，来塑造自己的身躯，偶尔会自言自语，似乎是在安抚不听从的灵魂。" },
  "159": { "n": "多灵主", "e": 14, "r": 2, "d": "它将所有灵魂彻底地融为一体，逐渐理解了一切。一位魔法学院的教授曾评价过：多重灵魂的共存是一种悲壮的、为了自我生存的努力。" },
  "160": { "n": "多菇丁", "e": 5, "r": 2, "d": "“又有了新的发现，多菇丁埋地时，是在通过菌丝体往地下传播信号，向其他菇精灵发出指令，它们信号的语言结构和古文字非常相似，也许它们的历史远比洛克以为的要早得多。”" },
  "161": { "n": "恶魔狼王", "e": 15, "r": 3, "d": "恶魔狼王是由族群内的强者通过决斗产生，胜者会以舔舐败者额头的仪式，宣告新统治的建立，当族群遭遇强敌时，恶魔狼王会断后掩护，即便身负重伤也绝不退缩。" },
  "162": { "n": "恶魔红钻", "e": 10, "r": 3, "d": "喜欢在洞穴的暗处歇息，会提前布好精细且带有剧毒的网守株待兔。步足末端布满危险的剧毒，尖锐而坚硬的触足既能用作进攻的矛，也能用作防御的盾。" },
  "163": { "n": "独角龙", "e": 5, "r": 1, "d": "" },
  "164": { "n": "翡翠水母", "e": 3, "r": 1, "d": "柔软的精灵，通过收缩身体喷水在水中前进。会使用触手释放毒素，以此麻痹对手，然后将其拖入水中。" },
  "165": { "n": "翻翻蝠", "e": 12, "r": 2, "d": "" },
  "166": { "n": "耳翎瑰魅", "e": 15, "r": 2, "d": "耳边的翎毛可以隔绝大部分声音，是非常好的隔音材料。研究人员从翎毛的特征入手进行分析，发现其在越嘈杂的环境下探测魔力的能力越弱，且自身魔力溢出现象越明显。" },
  "167": { "n": "费曼", "e": 13, "r": 1, "d": "被某个古老贵族世代圈养的种族，几乎褪去了野生的天性，无法通过精灵的手段在野外生存。个体均沿袭了贵族般的礼仪与行为，但翻看历史发现整个种族的社交状态堪忧，除了洛克族之外，几乎没有与任何精灵保持友好联系。" },
  "168": { "n": "费格尔", "e": 13, "r": 2, "d": "似乎是出于自愿跟随贵族，契约世代守护，以执事自称。世世代代的费格尔们在精灵语和洛克语对比研究方面做出了极大的贡献。精灵语翻译法则也冠上了他们种族的名字。" },
  "169": { "n": "飞天刀螂", "e": 10, "r": 1, "d": "十分冷静有耐心的种族，可以长久埋伏观察，一旦发现机会就会迅速出击，一击必中。雄性捕猎欲相对更强烈，借由其趋光性而捕捉到的个体几乎全为雄性。" },
  "170": { "n": "伏地兽", "e": 0, "r": 1, "d": "柔韧的吻部十分有弹性，没有牙齿，用舌头和吻部配合嘬取食物。每天吃几十只蚂蚁就可以存活，能量消耗很小，多数时间在睡觉。" },
  "171": { "n": "古卷匣魔像", "e": 0, "r": 3, "d": "“盗贼撬开了书库的大门，随后就被黑暗中什么沉重的打击在空中划出了一道抛物线。然后落荒而逃，并且拒绝再次到访这里，并且嘴里一直嘟囔着：知识就是力量”——某冒险者叙述他们在魔法学院遭到古卷匣魔像攻击的故事。" },
  "172": { "n": "古齿帝牙", "e": 6, "r": 1, "d": "" },
  "173": { "n": "格兰球", "e": 1, "r": 3, "d": "格兰球的花瓣持续生长与更替，老化花瓣会化作鳞片般的护甲。护甲上黏附诸多致痒花粉，它们热衷于边笑边蹭其他精灵。但洛克研究学者经观察其表情和动作发现，它们坏笑时鳞片般的护甲会微微张开，让它们更好地传粉。" },
  "174": { "n": "格兰花", "e": 1, "r": 2, "d": "格兰花头顶可喷射出具有不同功效的花粉，花粉沾身会致痒。它总是带着些许挑衅的眼神看着对方，似乎有意识地引诱对方来打自己，被打能帮它挠痒痒，而击打它时还会传播其花粉。" },
  "175": { "n": "格布布", "e": 6, "r": 2, "d": "" },
  "176": { "n": "格斗小五", "e": 11, "r": 3, "d": "执着于进行腿法训练，能够在瞬间发动数次踢击。得益于发达的腿部肌肉，在奔跑时有着极强的爆发力，乐于向遇见的一切生物发起竞速挑战。" },
  "177": { "n": "格斗小八", "e": 11, "r": 3, "d": "三三两两聚集在一起快乐乱舞，原因不明。偶尔会伴随着律动起舞，似乎能通过舞蹈与其他同伴建立起某种奇妙的精神链接。" },
  "178": { "n": "格斗小六", "e": 11, "r": 3, "d": "掌力十足,岩石上常常出现它们的掌印。研究员根据其攻击招式,改编了一套能够强身健体的健体操,在学院中曾挂起过一阵不小的习武之风。" },
  "179": { "n": "格格布", "e": 6, "r": 1, "d": "" },
  "180": { "n": "粉咩咩", "e": 8, "r": 2, "d": "经常看到它们聚在一起胡乱放电，放电的时候会跳奇怪的舞蹈，十分开心的样子。如果埋进它们的毛里猛吸一口，被电很惨同时闻到糊糊的怪味。" },
  "181": { "n": "粉星仔", "e": 17, "r": 1, "d": "习性和语言都与目前所知的任何精灵种族不同，身体轻盈，皮肤柔软但极其有韧性。研究学者偶然拾取到它星星飘下的碎屑，密度极高但质量非常轻，研究发现其材质也不属于卡罗西亚大陆的任何一种已知材质。" },
  "182": { "n": "粉粉星", "e": 8, "r": 1, "d": "身体里流淌着神秘的星光能量，打喷嚏的时候会下星星雨。喜欢聚在一起舞蹈，舞蹈时能看到漂亮的星光在它们周围环绕，推测这是粉粉星们交流的一种方式。" },
  "183": { "n": "粉耳星兔", "e": 17, "r": 3, "d": "踏着流星而来的信使，在洛克族里传闻对着它们说话有概率可以梦想成真。它们总是很着急，在夜幕下如同一道道银针般穿行，谁让这世间的许愿总是太多、太多了呢。" },
  "184": { "n": "风暴战犬", "e": 2, "r": 3, "d": "它的冠毛与尾巴像火焰一样摇曳，这代表它体内的火元素的热流外显，它的斗志一旦被点燃，会化作更强的火势与更可靠的压制力。" },
  "185": { "n": "高脚鹬", "e": 12, "r": 3, "d": "拥有较大的脑容量，是运筹帷幄的猎手，坚硬的帽形结构有良好的散热性，会用巨大的头部和双翅在水面上围出一片阴影，以此吸引喜欢在阴凉处生活的水生生物，静待着来乘凉的鱼虾进入它的捕猎范围。" },
  "186": { "n": "乖乖鹄", "e": 12, "r": 1, "d": "羽毛有很好的疏水性，可以毫不费力地浮在水面上，浮着的时候怔怔地看着水面，并不是在发呆，而是在检查自己的美丽，小小的乖乖鹄很早就已经意识到了美丽与优雅的重要性。" },
  "187": { "n": "光纤兽", "e": 4, "r": 2, "d": "毛发柔软但有韧性，结构特殊，似乎每一根毛发都能接收和发射光能量。它们可以分辨来自四面八方所有光束的到达时间，比较每个光束抵达的时间，计算其距离和能量。" },
  "188": { "n": "古卷执政官", "e": 0, "r": 3, "d": "期末时期的图书馆，每当古卷执政官从书架间缓缓现身，它周围的位置总被围得水泄不通，它的古卷如臂膀般展开，书页无声翻动，精准停在学生们最需要的章节上。“不要抗拒，作业是你和知识之间的契约。”" },
  "189": { "n": "古啦多", "e": 9, "r": 3, "d": "头部突起越复杂代表着年龄越大，突起内部充斥剧毒毒液，被一层外套膜包裹起来。遇到危险时，会释放更为强大的致幻毒素，但是并不致命。因此，部分洛克因为想要致幻体验，而专门寻找它们。" },
  "190": { "n": "古拉海象", "e": 6, "r": 1, "d": "拥有能够凝水成冰的能力，会钻到成群的沙丁鱼中，操纵冰锥捕猎。能达到数百千克之重，会选择在较厚的冰层上沐浴阳光，喜欢拍打肚皮上堆叠的脂肪。" },
  "191": { "n": "害羞球球", "e": 5, "r": 2, "d": "有时会将头上的部分发射出去，但不论多远都能收回来。似乎还有一种说法认为上面的部分才是本体，害羞地把自己隐藏了起来。" },
  "192": { "n": "寒音蛇", "e": 13, "r": 3, "d": "拥有能分泌毒液的特殊腺体，能够通过背部空心管状的骨棘发射毒液，致使猎物晕厥。毒液会散发出腐臭的气味，有精灵或洛克靠近查看味道来源时，会猛然跃起扑击。" },
  "193": { "n": "河马巴斯", "e": 0, "r": 1, "d": "" },
  "194": { "n": "海盔虫", "e": 3, "r": 1, "d": "它静止时像不起眼的礁石，让人很难判断这是不是生物。它以底栖方式缓慢移动，活动量与食物多少直接相关，食物少时一天可能只挪动一点点。棘刺间分布感光细胞，使它对强光十分敏感，常本能地躲向阴影。" },
  "195": { "n": "海豹船长", "e": 11, "r": 3, "d": "由聪慧且经验丰富的海豹战士进化而来，拥有极强的领地意识。这一物种对征服由极端的渴望，认为其他精灵都要臣服于它们。会指挥手下的海豹战士战斗。" },
  "196": { "n": "瑰眼仔", "e": 15, "r": 1, "d": "总是缩在某个角落里不知道在想些什么，看似脑袋空空双眼无神，一副呆呆的样子。额头上第三只眼睛不是用来作为视觉器官，而是用来探测魔法能量的痕迹，使用时需要放空所有杂念。" },
  "197": { "n": "黑炎", "e": 7, "r": 2, "d": "喜怒无常，几乎不进入睡眠，浅眠的时候如果监测到周围的危险会变得非常暴躁。检测后发现其处于灵魂残缺的状态，身体中流转的大量高阶魔法，猜测这些高阶魔法是用来填充缺失的灵魂。" },
  "198": { "n": "黑猫密探", "e": 0, "r": 3, "d": "拥有了在黑暗夜空中穿行的能力，据说它们能读取宇宙中所有星光的讯息，预知即将发生的危机。小洛克常常发现，当黑猫密探突然变得异常安静时，往往预示着某种变故即将来临。" },
  "199": { "n": "黑猫巫师", "e": 0, "r": 3, "d": "夜晚总是在看星星，长久地观察星空和白天不停地思考，似乎让它们拥有了占卜的能力。偶尔会看到有小洛克拿着可可果去拜托黑猫巫师帮忙预测期末考试题。" },
  "200": { "n": "化蝶", "e": 10, "r": 3, "d": "极其聪慧的种族，大脑占去整个身体的三分之二。翅膀有力，充满魔力的鳞粉形成了翅膀上的花纹，用以迷惑其他精灵。" },
  "201": { "n": "呼拉猫", "e": 11, "r": 1, "d": "每只减肥猫都会遇到它命中注定的小蛇，和小蛇一起可以开开心心的运动。没人见过没有小蛇朋友的减肥猫，可能是孤单一只猫根本没办法坚持下去。" },
  "202": { "n": "幻影荆棘", "e": 14, "r": 3, "d": "拥有族群特有的魔法诱导型次生生长手臂，左臂与右臂化作两根巨大的带刺藤蔓，可以自主做出抓取、摆动等动作。远远看去，像三棵高低不同的枯树一起移动。" },
  "203": { "n": "幻灵菇", "e": 14, "r": 2, "d": "头顶的触角比隐藏在伞盖下的面目更能够表达出心情，悄无声息地飘来飘去，通常出现在后半夜。在森林深处大量聚集，散发着淡淡荧光，会吸收周围植物和小型动物的情绪。" },
  "204": { "n": "幻雪兽", "e": 6, "r": 2, "d": "" },
  "205": { "n": "忽幽狸", "e": 14, "r": 1, "d": "忽幽狸的尾巴覆盖着剧毒尖刺，静止时会伪装成灌木枝条。当感知到危险，尾巴会瞬间硬化成防御姿态，刺尖分泌的神经毒素能使猎物肌肉僵直。检测显示，其毒素对草系精灵效果加倍。" },
  "206": { "n": "画像守护", "e": 0, "r": 2, "d": "可以熟练地在画中与画外穿梭，十分热心肠，喜欢交朋友，经常为认识的画做保养，轻轻吹走灰尘，灰尘太多可能令它一直打喷嚏。但这并不会成为它们的阻碍。" },
  "207": { "n": "画精灵", "e": 0, "r": 1, "d": "画中世界诞生的精灵，活泼好动，对穿梭魔法的运用不是很熟练，偶尔会被画框卡住。曾经尝试少吃可可果来解决这个问题，后来发现并没有效果。" },
  "208": { "n": "画间沉铁兽", "e": 0, "r": 3, "d": "一种沉默寡言的分支形态，稍微有些粗鲁，比起结识更多的朋友，对它来说更重要的是保护现在朋友们的安全，可能在实施保护中不小心磕到朋友的头。确定了需要保护的对象之后，就不会再四处穿梭。" },
  "209": { "n": "画间法师手", "e": 0, "r": 3, "d": "能够通过画框跨越时间与空间，沉迷于收集更多的见闻，看见更广阔的世界。在长年累月的穿梭中，曾经认识的画已经褪色，但它从没有停下。" },
  "210": { "n": "红丝绒", "e": 2, "r": 2, "d": "绒毛里储存着温和的火系能量，抱在怀里就像一个小暖炉，身体散发出煎药的香味。它特别喜欢照顾受伤的精灵，会用温暖的鼻息轻轻吹拂伤口，伤口就不痛了。" },
  "211": { "n": "红绒十字", "e": 2, "r": 3, "d": "头顶的十字结构能释放出强效的治愈魔法，轻轻一碰就能缓解肌肉酸痛，伤口也会加速愈合。如果看到受伤的精灵但无法施救的话会流泪不止。" },
  "212": { "n": "花影羚羊", "e": 14, "r": 3, "d": "进化后，分叉的角更为锋利，中间盛开一朵蓝色花朵，花瓣能体现它们的身体状态，疲劳时，花瓣会略微下垂。花朵在夜晚能发出怪异的微光，能够迷惑对手。" },
  "213": { "n": "花衣蝶", "e": 10, "r": 3, "d": "原本的尾巴脱落后变成手中的花朵，似乎蕴含着魔法能量，能当作魔杖使用。冬日寒冷的雨夜里，成千上万的花衣蝶聚集在枯树上休息，清晨又四散飞走，如同花开一夜的蜃景。" },
  "214": { "n": "花魁蜂后", "e": 10, "r": 3, "d": "只有最尊贵的蜂后能得到加冕，穿着金色的华美虫衣，有淡淡的花香味，女王蜂以信息素的方式向周围的蜂群传递自己的命令。" },
  "215": { "n": "黑炎宝宝", "e": 7, "r": 1, "d": "革质的双翼坚韧而有力，可以低空飞行。爪和下颚的力量已经超过其他成年精灵许多。双角是外生的骨骼，每年蜕一次，每次会变得更加坚硬锐利，蜕下的龙角据说是上好的药材，千金难求。" },
  "216": { "n": "黑羽夫人", "e": 12, "r": 3, "d": "天鹅精灵中罕见的独居分支，对社交并不热衷。羽毛长而卷翘，摸起来有些刺手，似乎并不符合种族中普遍的审美，但自信令她看起来非常优雅。" },
  "217": { "n": "加尔", "e": 14, "r": 1, "d": "" },
  "218": { "n": "加灵", "e": 0, "r": 1, "d": "" },
  "219": { "n": "加益", "e": 0, "r": 2, "d": "" },
  "220": { "n": "坚角龙", "e": 5, "r": 2, "d": "" },
  "221": { "n": "寂灭骨龙", "e": 7, "r": 3, "d": "当被从土层里挖出来的时候，它们正在一无所知地睡觉。别看它们脆弱得好像一脚会散架，但埋了亿万年的矿物硬度堪比钻石。“它总是对着镜子思考，幻想自己当年活着时候的样子。”" },
  "222": { "n": "幻影灵菇", "e": 14, "r": 3, "d": "仅仅看到它触角上闪烁的荧光就会头痛难耐，对其研究很难有进展。没有生命迹象但是可以自如活动，无法判定是植物还是生物，唯独颈间圆环中似乎蕴含强大生命力。" },
  "223": { "n": "机甲小子", "e": 16, "r": 3, "d": "只在有需要的时候出现，每当齿轮小子遭遇危机，就会化身机甲，严格按照程序执行正义。危机解除后，会重新变回齿轮小子。偶尔会迟到但但是却从不会缺席，就像正义一样。" },
  "224": { "n": "混乱鱿彩", "e": 14, "r": 3, "d": "体型暴涨，皮肤化作流动的红、蓝、黄三色漩涡，情绪高涨时随时像泼墨般炸开。它用触手当画笔，在空中乱甩墨汁，留下大片狂野的色块。" },
  "225": { "n": "火尾战士", "e": 2, "r": 2, "d": "经常看到它在磨爪子，磨得发烫了才会停下。在战斗前会加热自己的身体以提升力量，有时甚至会让整个头顶的毛发燃烧起来。" },
  "226": { "n": "火焰猿", "e": 2, "r": 3, "d": "哪怕是休息的时候，也像沉睡的火山一样危险。岩浆涌动的身体需要经常添加燃料，偶尔会把吃不完的食物丢到头顶的火山口里燃尽。" },
  "227": { "n": "火神", "e": 2, "r": 3, "d": "强大的火焰之灵，只是靠近它就能够感受到温度的急剧变化。如果没有脖子上的项圈，它的火焰可能会暴走。“在磨练中成长，在烈火中重生，用意志在战斗，用生命在燃烧，永远的火神”。" },
  "228": { "n": "火红尾", "e": 2, "r": 1, "d": "" },
  "229": { "n": "火羽", "e": 2, "r": 1, "d": "在空中飞翔的时候火焰也席卷全身，好像天空中划过一道火痕。和想象的不同，飞翔的力量更多来自它尾部喷射的火焰，而不是翅膀。" },
  "230": { "n": "火花", "e": 2, "r": 1, "d": "像一团迸发的小火花，坦诚炙热，生性勇敢无畏。能熟练运用火元素，偶尔有点冒失，是值得信赖的伙伴。" },
  "231": { "n": "疾光千兽", "e": 4, "r": 3, "d": "在月亮升起来之后活动，某些特定时间会散发出微弱光芒，与某些弱小的夜行生物存在共生关系。光能量在每根毛发中沿“之”字形向身体内部传输，可以完好无损地传输到体内，存储凝结成强大力量。" },
  "232": { "n": "祭礼巨像", "e": 5, "r": 3, "d": "它们是远古星象祭典的传承者，将观测到的星轨运行规律铭刻在体表，延续着文明的脉络，身上的古文字符号已超出当代洛克的认知范畴，无法被识别解读。" },
  "233": { "n": "黄蜂后", "e": 10, "r": 2, "d": "在蜂后的下半身周围有能量波动，推测是用来建立两只小蜂的联系。战斗时，蜂后的两眼会变成红色，针刺也会变得锋利无比。" },
  "234": { "n": "九尾狐", "e": 2, "r": 2, "d": "尾巴里储存着强大的魔力，能够释放一种特殊的雪魔法，保护越冬作物免受冻害、消灭土壤中害虫，如果在冬天的农田里看到九尾狐出现，就知道明年一定会丰收。" },
  "235": { "n": "九幽菇", "e": 5, "r": 3, "d": "“在古老的遗迹中发现了九幽菇的石雕，当时的洛克对九幽菇充满了崇拜，他们会在仪式上围着九幽菇唱歌，并在祭祀的指导下服用其孢子，进入幻觉，企图沟通神明，然而也存在接触它的孢子太久而神志不清的情况，等等，难道我也……”" },
  "236": { "n": "健猫教练", "e": 11, "r": 1, "d": "学习了名为“蛋白粉法术”的迷之魔法，身形也因为练习“蛋白粉法术”而发生了变化。种群里部分群体会偷偷使用一种和炼金药剂配合的黑魔法，能快速改变身形，但是会伤害身体。健身也是为了提升自己的武力，不能得不偿失哦。" },
  "237": { "n": "剧毒魔蝎", "e": 9, "r": 1, "d": "借助风来移动的精灵，碰到水的时候会停下来休息。" },
  "238": { "n": "卡拉波斯", "e": 15, "r": 2, "d": "据传说卡拉波斯曾经是一个仙子，因为误会诅咒过一位公主，被诅咒反噬后变为纺锤的模样。一次最多能够拉出7000米纺线。当体内的蛋白质耗尽的时候，它们就不会再进行任何活动陷入永久的昏睡中。" },
  "239": { "n": "卡波", "e": 15, "r": 1, "d": "能够生产出纺线的精灵，纺线主要由卡波体内的蛋白质和唾液构成。卡波的唾液中带有某种未知诅咒，即使是同类触碰到的话也会中毒陷入昏睡。" },
  "240": { "n": "卷毛鸭", "e": 1, "r": 3, "d": "身形与洛克近似，空洞的目光仿佛若有所思。头顶的毛发十分柔软，自然卷曲，这在鸭精灵中十分少见。" },
  "241": { "n": "卷胡巨獭", "e": 0, "r": 3, "d": "对外表有蛮高的追求，除了磨牙的习惯之外，体内分泌的油脂会被用来保养胡须。蓬松的胡须和锋利的牙齿代表其在族群中的地位，部分獭会去寻找枯草装作假胡子戴着。普遍不喜欢和洛克亲近。" },
  "242": { "n": "咔咔壳", "e": 3, "r": 2, "d": "很少再缩进壳里，即使遇到危险也会勇敢面对。甲壳内一部分是空气，一部分是水，通过喷嘴来调节重量从而在水中下潜和上浮。" },
  "243": { "n": "咔咔羽毛", "e": 12, "r": 1, "d": "跑得很快，手短且柔软，一般用尾巴来代替手的作用。尝试助跑之后短暂地浮空，但似乎一直没能学会飞翔。" },
  "244": { "n": "咔咔雀", "e": 12, "r": 2, "d": "仿照洛克号的帆进化出了大尾巴，曾经尝试练习滑翔，大尾巴让它们能够短暂浮空，也可以用来吓唬和拍打敌人。" },
  "245": { "n": "咔咔鸟", "e": 12, "r": 3, "d": "拥有两条漂亮的大尾巴，虽然无法飞翔，但是抓着大尾巴可以滑翔一段距离，滑翔时身体散发出香香的味道，是因为这个种族普遍有些恐高，紧张的时候会释放舒缓神经的信息素，为自己壮胆。" },
  "246": { "n": "堇楹苞", "e": 9, "r": 1, "d": "" },
  "247": { "n": "尖嘴狐仙", "e": 2, "r": 3, "d": "尖嘴狐仙能通过感知大地的温度变化来预测农时。当它摇着尾巴经过农田时，尾巴扇动的气流会形成特殊的暖湿环流，让田地在寒冷的初春也能保持适宜作物生长的温度。" },
  "248": { "n": "尖角蜘蛛", "e": 10, "r": 2, "d": "各关节覆盖着绒毛，绒毛可以疏水和保暖。在湿滑的雨天也可以自由行走，世界的动态在它们眼里显得很慢，所以大部分尖角蜘蛛都是急性子。" },
  "249": { "n": "巨噬针鼹", "e": 0, "r": 3, "d": "体表坚硬的鬃毛能够防御风吹日晒和敌人的攻击。长舌灵活而柔韧，能够绊倒猎物或者缠绕颈部使其窒息，吻部如同长矛一般刺穿猎物的要害，甚至可以击穿岩石。" },
  "250": { "n": "巨灵石", "e": 5, "r": 3, "d": "从大地获取强大的能量，可以使用地系魔法操纵土壤石头。常常收集一些土壤，石块作为零食，喜欢边讲故事边嚼石头，洛克族的孩子们偶尔会躲在旁边偷偷听它们讲故事。" },
  "251": { "n": "爵士鹿", "e": 8, "r": 3, "d": "即使在野外遇到也不会贸然攻击，目光对视时会礼貌鞠躬。它能更精细地调整头顶电球的电流强度：既可用于攻击与照明，也可配合节奏稳定输出，进行电疗治疗伤病。" },
  "252": { "n": "荆棘电环", "e": 8, "r": 3, "d": "总是会发出意义不明的“哔哔”声，似乎使用这种声音诱敌。表情看起来更加痛苦了，仿佛电力在体内循环本身就是一种负担。" },
  "253": { "n": "卡洛儿", "e": 3, "r": 3, "d": "有些呆，不论交给它们什么东西，都会用心地放进自己的壳里。如果能找到办法和它们交流的话，它可能会从螺壳里拿出意想不到的东西作为礼物。" },
  "254": { "n": "可爱猿", "e": 2, "r": 1, "d": "头顶着活跃的微型火山，就连睡觉时也会冒出小烟圈。可别因为体型而小看了它，可爱猿头上流出的熔岩就连钢铁也能融化。" },
  "255": { "n": "壳乙螺", "e": 3, "r": 2, "d": "生活在螺壳里，似乎对壳外面的世界不太关心，多数时间都躲在壳里睡觉，对食物的香味比较敏感，可以用食物引诱出来。" },
  "256": { "n": "壳栗丝鼠", "e": 9, "r": 2, "d": "会嗅来嗅去寻找花蜜，吃的花蜜越多，鼻子分泌的粘液越香甜，并且带着花香的味道。" },
  "257": { "n": "岚鸟", "e": 12, "r": 3, "d": "眼神锐利，有着绅士般冷静而又端庄的非凡气质，让它在贵族当中颇有人气。胸腹绒羽形成稳定的隔热层，能在强风中维持体温，拥有较强的耐力。" },
  "258": { "n": "库多西", "e": 16, "r": 2, "d": "兼具岩石的稳固与钢铁的坚韧，身上带有厚重的泥土气味，推测是因为习惯在地底休眠所致。能够利用磁场的力量发动攻击，但也会在特殊磁场的影响下动弹不得，因此总是在人烟稀少的地方栖息。" },
  "259": { "n": "快鳍鱼", "e": 3, "r": 2, "d": "额部鼓起突出，中空有气囊，可以自由改变前额的形状，推测可能是借着移动内部空气来产生形状上的变化，潜水能力相当强，甚至可以一边在水下灵活旋转一边发出多变的叫声，呼唤着同伴，吟唱着记忆深处关于化龙的古老歌谣。" },
  "260": { "n": "瞌睡王", "e": 0, "r": 3, "d": "比较难找到它的眼睛，主要靠鼾声来判断它是不是醒着。即使危险就在面前也能睡得香香的，或许是强大的体格给了它这样做的底气。" },
  "261": { "n": "矿晶虫", "e": 4, "r": 1, "d": "喜欢攀附于潮湿的岩层，以土壤中的矿粒为食，常被用作衡量矿产资源丰富度的标志。身上的晶体可以将细小的光线通过折射放大数倍，四只矿晶虫便能照亮一整个矿洞，是备受矿工喜爱的精灵。" },
  "262": { "n": "空空颅", "e": 14, "r": 1, "d": "夜晚很容易在破旧的空屋见到。力量弱小但长着骇人的面容，会恐吓其他精灵，以此来保护自己。它几乎不依赖视觉，通过感知热量来判断生物的位置与距离。" },
  "263": { "n": "蓝珠天鹅", "e": 12, "r": 2, "d": "有强烈美意识的种族，时常梳理羽毛，用珍珠来打扮自己。优雅的举止和良好的外表是向同伴传递自身健康强壮的信号，拥有的珍珠数量也决定了自身在种群中的地位。" },
  "264": { "n": "蓝蝶鲨", "e": 3, "r": 2, "d": "它的身体构造至今难以完全解释：体内几乎都是水，身体被一层透明的膜包裹住，里面的液体非常轻。飞行时，由于压力变化或者风势太大，液体有时会漏出来。" },
  "265": { "n": "蓝衣夜灵", "e": 5, "r": 1, "d": "身上有着大块石英材质，就像穿着衣服一样。对石头的操控非常熟练，能够利用头上悬浮的散石发动难以预测的攻击。" },
  "266": { "n": "酷拉", "e": 8, "r": 3, "d": "能利用电能量高速移动，偶尔也会发生意外事故与同类相撞，交流时会发出“噼啪噼啪”的声音。" },
  "267": { "n": "铠甲虫", "e": 10, "r": 3, "d": "全副武装没有破绽，头顶的巨钳令人生畏。甲壳有些沉重，依然可以飞行。但好处是，厚重的甲壳能够挡住敌人的攻击。" },
  "268": { "n": "雷暴奔奔", "e": 8, "r": 1, "d": "不知道为什么在野外遇到它们的时候，它们一直在哼歌，断断续续的小调不清楚是什么曲子，但非常洗脑。使用复杂的声音和曲调进行交流，它们哼的歌里面包含了想要传递给对方的信息。" },
  "269": { "n": "雷鸣小子", "e": 8, "r": 2, "d": "额前虽然有闪电的印记，但平时似乎并没有包含任何电系能量。周围有音乐响起的话，会迅速进入带电状态。常看到三三两两的霹雳宝宝聚在一起一边发出电光，一边蹦跳。" },
  "270": { "n": "利刺毒蝎", "e": 9, "r": 1, "d": "借助风来移动的精灵，碰到水的时候会停下来休息。" },
  "271": { "n": "利灯鱼", "e": 3, "r": 3, "d": "独居生物，个体之间保持距离，互不侵犯。常常自言自语，狂笑乱跳。据研究它们头顶的灯内有百万只以上的发光菌，肉眼很难观察。每只菌似乎都有独立意识，能够和本体进行沟通，甚至还有可能侵蚀本体的脑。" },
  "272": { "n": "厉毒修萝", "e": 9, "r": 3, "d": "翼上的毒棘带有能够分泌剧毒的腺体，狩猎时常在暗处蹲守观察许久，找到时机后从棘刺中射出毒液使猎物昏迷，再飞速捕获。" },
  "273": { "n": "厉毒小萝", "e": 9, "r": 1, "d": "体味清香，翼下藏有数个腺体，能够发射致洛克晕厥的毒雾。受惊时将双翼展为扇形，倾泻毒雾后迅速逃离。" },
  "274": { "n": "厉毒鸩兽", "e": 9, "r": 1, "d": "" },
  "275": { "n": "栗鼠", "e": 9, "r": 1, "d": "身体会散发烤栗子一样的香甜气味来吸引异性，其身体粘液是洛克制作饼干的材料，香甜又有嚼劲，广受欢迎。" },
  "276": { "n": "流浪鼠", "e": 5, "r": 3, "d": "背后鼓鼓的行囊里是更多捡来的收藏品，闪闪发光的物体对它们有着无与伦比的吸引力。不论是亮晶晶的小石子，闪着微光的菌类，还是洛克不小心遗落的饰品。在劳累之后，它们也会静静地在波光粼粼的水面望着月亮。" },
  "277": { "n": "灵羽勇士", "e": 12, "r": 2, "d": "弱小的家伙为了伙伴却愿意勇敢向前！光羽圣殿的门扉悄然开启，沐浴在圣光之力的启迪中，澎湃的力量汹涌而来。“它的思绪已沉醉在无垠的天际中，这片蓝天便是它魂牵梦绕的地方”。" },
  "278": { "n": "灵蔓草王", "e": 1, "r": 1, "d": "身形修长而优雅，身边围绕的藤曼一边枯萎凋零，新芽却又在枯萎处悄然生长，进行着生命的轮回，掌控着生命与死亡的力量。" },
  "279": { "n": "烈火守护", "e": 2, "r": 3, "d": "在草原上全速奔跑的时候时常引发火灾。毛发蓬松且疏水，毛发内部均能发现未燃尽的火星。被驯服后性情极其温顺。" },
  "280": { "n": "烈火战神", "e": 2, "r": 3, "d": "“在磨练中成长，在烈火中重生，用意志在战斗，用生命在燃烧，永远的火神”。" },
  "281": { "n": "烈钻鸟", "e": 2, "r": 1, "d": "羽毛上的花纹预示着它是会使用火焰的鸟精灵。快速地啄击树木的话，会把整颗大树燃烧起来。" },
  "282": { "n": "獠牙猪", "e": 6, "r": 3, "d": "身躯看似圆润，但其实十分健壮灵活，拥有令人意想不到的爆发力，即使在冰天雪地里，也非常有活力。" },
  "283": { "n": "琉璃水母", "e": 3, "r": 3, "d": "身体的触手花纹会随心情变化，游动时非常漂亮。是海边生活的洛克的艺术灵感来源。然而它长长的触手可以释放多种效果的攻击，被它的美丽吸引注意时，可能会陷入危险哦。" },
  "284": { "n": "立叶蜥", "e": 1, "r": 2, "d": "立叶蜥被称为翠绿流星，头顶的松果体让它们就像长着第三只天眼，在迷宫似的森林里自带罗盘，脚底的吸盘让它们在过弯时稳抓地面，就像翠绿的流星一闪而过。" },
  "285": { "n": "立方人", "e": 16, "r": 3, "d": "能够听懂和使用洛克族语言，了解洛克族的礼仪和社会结构，会模仿洛克族的行为，甚至会与其他个体组建家庭。“勤奋的他，总是不停地前行，心中在默念：每个人努力过都不普通。”" },
  "286": { "n": "里奥", "e": 12, "r": 1, "d": "有着圆滚滚的身躯，小小的翅膀还无法熟练飞翔，却能和愿力发生共鸣，从而获得力量。“和伙伴在一起的安全感连美食都不能替代。即使有时候像个小跟屁虫也无所谓。”" },
  "287": { "n": "铃兰羊", "e": 14, "r": 2, "d": "白天会懒洋洋地趴在草原上休息，主要在早晨和黄昏行动，一般会脱离种群独自生活。跳跃力惊人，在山坡上如履平地，从100米的高度一跃而下也没事。" },
  "288": { "n": "帽兜娃娃", "e": 6, "r": 2, "d": "头部浓密柔软的绒毛负责锁住热量，形成高效的保暖屏障，减少温度流失，兜帽形态的头部结构也可以有效防风。同种族喜欢聚集在一起，贴着脑袋，发热保暖。可能因为这种地缘因素，它们产生了一些社会性和群居属性。" },
  "289": { "n": "梦想三三", "e": 13, "r": 3, "d": "咻咻咻！听到“喵呜”一声的小洛克们请立刻拿出课本做好，魔法学院开课了！请牢记以下守则：请勿在课堂上投喂助教，请勿拉扯助教的尾巴，请勿对助教发出“嘬嘬嘬”等不尊敬的声音！" },
  "290": { "n": "梦残卷", "e": 17, "r": 1, "d": "" },
  "291": { "n": "毛头小蛛", "e": 10, "r": 1, "d": "身上的绒毛柔软且密集，表面有微小的鳞片结构来吸附灰尘，喜欢从灰尘中吸食各种魔法粉尘，会追逐星星魔法，并吸食炸开的粉末。遇到洛克时容易惊慌失措，全身颤抖，在刺激下炸毛，身上的灰尘也被抖落，让洛克忍不住打喷嚏。" },
  "292": { "n": "煤球憨憨", "e": 5, "r": 1, "d": "在矿洞中与石头作伴，无忧无虑地生活着，性情温和憨厚。用尚不成熟的魔力将两块石头牢牢吸在头顶，那似乎是它很珍视的东西，生怕弄丢了。" },
  "293": { "n": "绿洲象", "e": 1, "r": 1, "d": "生活在高海拔地区，演化出了茂密而厚实的皮毛，不仅能抵御雪山的寒冷，还能阻挡普通的攻击。叶片状绒毛的结构与远古时期的植物相似，能够吸收阳光来为自己供给能量，借此熬过雪山上漫长的冬季。" },
  "294": { "n": "绿草精灵", "e": 1, "r": 1, "d": "在森林里挥舞着手中的木棍，好像是在做施放巫术的练习。偶尔会和帽子交谈，晒太阳的时候可能会发出诡异的笑声。" },
  "295": { "n": "罗隐", "e": 5, "r": 3, "d": "身体中结晶脉络光滑透亮，十分坚硬，似乎是某种矿石。长着凶狠的样貌，揣着不知如何表达的善意，示好的时候会展示一下由石头构成的肌肉。" },
  "296": { "n": "落星虫", "e": 10, "r": 2, "d": "与精灵缔结契约的形式发生变化，咕噜球的样子世代更替，这一种族的外表也渐渐发生了变化。有人曾经尝试使用特殊咕噜球喂食，虫的形态在数年后发生变化，但实验没有继续下来，猜测是因为资金不足。" },
  "297": { "n": "落陨星兔", "e": 17, "r": 3, "d": "“能够在流星上倾听许愿的家伙，总会被认为是善良的吧？嘻嘻，它们可从来没说过会以什么方式实现哦！扭曲的实现也是实现。不愿以他人的理想为自己一生的追求，却也无法逃脱命运的桎梏。那么来吧，向它们许愿吧！”" },
  "298": { "n": "蔓羽兽", "e": 9, "r": 2, "d": "" },
  "299": { "n": "觅觅蝠", "e": 12, "r": 1, "d": "常出现在垃圾堆和阴暗潮湿的洞穴里，常看到它们同类之间碰碰鼻子交流。看起来似乎是鼻子的部分用来放出声波探测周围信息，对味道的感知几近于零。" },
  "300": { "n": "迷迷箱怪", "e": 16, "r": 3, "d": "它们并不追逐也不恐吓，只是静静地埋伏，等待小洛克伸手想要开宝箱时，才会突然袭击。因此老练的魔法师们会说：“冒险不难，难的是抵达终点时敢不敢伸手。”" },
  "301": { "n": "鳗尾兽", "e": 5, "r": 3, "d": "它头部几乎没有视力，主要靠嘴感受气流来调整方向，偶尔会在地表横冲直撞。吼叫时会带动口中的吊钟形花朵震动，发出阵阵钟声。它们和同伴间通过这些声响，彼此交流。" },
  "302": { "n": "龙息帕尔", "e": 15, "r": 3, "d": "在古老的典籍中记载，龙息帕尔和其他恶系精灵的行事风格不同，它们秉持着等价交换的原则，会严格遵守自己缔结的契约。在契约完成前绝不会离开，甚至愿意为此等待漫长的时光。" },
  "303": { "n": "龙鱼", "e": 3, "r": 3, "d": "长鳍长尾，身形纤细流畅，拥有强大的游泳能力和跳跃能力，身体的结构比起鱼更接近龙，证明其拥有少量龙系血脉，尾部的红珠中蕴含着些许龙系能量，可以在跃出水面时发出真正的龙吼。" },
  "304": { "n": "喵呜", "e": 1, "r": 2, "d": "爱在泉水边嬉戏，是喵喵的进化型，芭蕉叶状的尾巴变成了两条。胆量变大了，会经常吐舌头挑衅对手。" },
  "305": { "n": "喵喵", "e": 1, "r": 1, "d": "喜欢阳光，喜欢新鲜的空气，会摇晃尾巴，受到惊吓会快速逃跑。虽然很胆小，但是也有时候非常调皮。" },
  "306": { "n": "喷火鸟", "e": 2, "r": 2, "d": "" },
  "307": { "n": "噼啪鸟", "e": 8, "r": 3, "d": "“你知道洛克的头发什么时候会竖起来吗？”“是你妈妈突然闯入你房间的时候？”“是进入了噼啪鸟的电场！我还听到它的吼叫声！幸好我跑得快，差点就被电击了！”“……不过这个发型还挺帅的，下次再试试。”" },
  "308": { "n": "墨鱿士", "e": 14, "r": 1, "d": "不同于章鱼精灵，它们因为蕴含幽系能量，皮肤已经褪成苍白的颜色，头足里面藏着墨囊，装着它们收集来的颜料。经常藏在厚厚的画纸中间休息。" },
  "309": { "n": "女王蜂", "e": 10, "r": 3, "d": "穿着披风、戴着王冠的蜂后，总是带着它的两个小侍卫。高雅的女王形象令人印象深刻，它的外形曾经是许多服装设计的灵感。" },
  "310": { "n": "帕尔萨斯", "e": 15, "r": 2, "d": "头顶的独角锋利又坚硬，但不蕴含魔法，脱落下来的独角最早被洛克用来制作匕首。“它眼中看到的都是黑白的，它的世界没有色彩，单一的世界却让它有了执着的信念和忠诚的心。”" },
  "311": { "n": "帕帕斯卡", "e": 16, "r": 3, "d": "在机械系精灵中非常有声望。曾经制造出帕帕斯卡的洛克许下一个愿望，希望能让机械系精灵有尊严地活着。于是帕帕斯卡们整个种族一直在想办法让机械系精灵过上更体面更开心的生活。" },
  "312": { "n": "怒目怂猫", "e": 11, "r": 3, "d": "胸脯处长着结构独特的气囊，能够迅速膨起至数倍大，形状像是血盆大口，可以吓退敌人。想回到正常姿势需要排出胸脯中的气体，排气的时候会发出非常可爱的声音，一般会在没有其他生物看到的时候偷偷排气。" },
  "313": { "n": "抹茶布丁", "e": 3, "r": 3, "d": "抹茶布丁负责舒缓与修复，它会释放带草本气息的挥发物，闻到这种气味，周围的生物会更容易安定下来。它们对同伴与洛克都很亲近，会抱住洛克身上的细小伤口，通过触碰治愈创伤。" },
  "314": { "n": "暮星辰", "e": 17, "r": 3, "d": "当知识积累到一定程度，曜星光便会和星辰共鸣，化身暮星辰。一颗星辰寂灭，一颗星辰升起。涌起的黑洞已然吞噬了它的心灵。无穷无尽的冰冷与空洞啊——但是它依然在等待，等待初生的行星，等待初生的小小洛克来到它的面前。" },
  "315": { "n": "泥吼牙", "e": 5, "r": 3, "d": "一口就能吞下比自己还重的淤泥，皮肤表面也有了吸收淤泥的能力，淤泥硬壳能有效保护它们脆弱的骨骼。有的时候不小心把小体型的精灵邻居吸到嘴巴里，会赶紧吐出来，连连道歉。偶尔也会用嘴巴载着小型精灵度过泥潭。" },
  "316": { "n": "爬爬", "e": 10, "r": 2, "d": "外壳硬化，缩腹在各种物体的表面爬行。背面艳丽的斑点看似有毒，实际上是鳞翅根。" },
  "317": { "n": "迷嶂布莱克", "e": 5, "r": 3, "d": "迷嶂布莱克的体型与山脉规模正相关，其骨骼密度可达普通岩石矿物的3倍以上，且骨骼内部存在类似“蜂窝结构”的减重设计——这种结构能在保持高承重能力的同时，减轻自身体重，迷障布莱克能承受的重量约为自身体重的100-150倍。" },
  "318": { "n": "迷迷眼", "e": 14, "r": 1, "d": "拥有奇特的双眼，似乎能看到身边人脑海里浮现的事物，以目前的知识完全无法理解其中构造。头顶的小圆球似乎是某种屏蔽装置，目前猜测可能是用于屏蔽过量的信息。" },
  "319": { "n": "霹雳宝宝", "e": 8, "r": 1, "d": "" },
  "320": { "n": "魔力猫", "e": 1, "r": 3, "d": "普遍性情温和，体型巨大，据说深吸一口气能呼出将洛克都吹走的狂风，但通常情况下举止动作十分轻柔。“长了三条锋利的尾巴，经常会用身体冲撞碾压对手。”" },
  "321": { "n": "魔眷鸟", "e": 13, "r": 3, "d": "似乎并非是自然产生的物种，对魔法的共鸣极强。根据调查统计结果来看，即使是野生的魔眷鸟也曾经有过契约者，怀疑是被制作出之后再放生的。" },
  "322": { "n": "魔翼鸟", "e": 13, "r": 2, "d": "巨大的翅膀能够给予敌人强有力的打击，旋转时更能提高打击效率。物理攻击和魔法攻击都很擅长，翅膀中蕴含着巨量魔力，翅膀内侧的脉络中是魔力流转的痕迹。" },
  "323": { "n": "魔草巫灵", "e": 1, "r": 3, "d": "守护着森林的小巫师，头上的帽子似乎已经跟随它多年了。帽子的两侧是它树叶状的耳朵，能听到树木之间的对话。" },
  "324": { "n": "千棘海刺", "e": 3, "r": 3, "d": "" },
  "325": { "n": "千棘海针", "e": 3, "r": 3, "d": "有少量报告称见到过如此奇异的精灵。似乎看一眼都会感觉到刺痛。身形大过鸟类，尖刺利过刀刃。已经无法找到虫体本身。它们再也不用担心保护自己的问题了，反而是别的生物需要担心这个。" },
  "326": { "n": "千棘盔", "e": 3, "r": 3, "d": "平时它仍行动迟缓。但遇险时能短暂加速，脱离光照与威胁区域。受到轻微触碰时，棘刺会迅速聚合，并指向接触点，棘端的毒囊能造成刺痛与轻微麻木。" },
  "327": { "n": "奇丽叶", "e": 1, "r": 2, "d": "头顶的花苞十分巨大，花苞成长速度已经超过身体，头部上方是视野盲区，由身体下面五个足状的突起维持平衡。" },
  "328": { "n": "奇丽果", "e": 1, "r": 3, "d": "头顶结出了橙红色的果实，散发出甜腻的香味，小鸟精灵可能会被吸引。但贸然接近是得不到好果子吃的，它分泌的糖胶不仅黏还有毒，无声拒绝着每一个不速之客。" },
  "329": { "n": "奇丽花", "e": 1, "r": 3, "d": "巨大的花朵盛开了，花瓣像是一顶遮阳帽，粗大的花蕊像触角一样，花朵很好闻，有类似柑橘的香甜气味，对小型精灵有强烈吸引力。" },
  "330": { "n": "奇梦咪", "e": 13, "r": 3, "d": "负责的喵老师为了让学生好好学习，想到了一种更直接的教学管理方式：只要有学生想溜出教室探头逃课，下一秒就会被它软乎乎却弹性十足的肚皮弹回座位。" },
  "331": { "n": "棋契陛下", "e": 11, "r": 3, "d": "在棋盘最中央的格子是为它预留的王座，棋契陛下并非被雕刻，而是由黑白两色棋子在万夜轮转中自行对局而生，它不移动，却可以传令所有棋子。“当王座离棋，棋盘即终局；终局之时，所有棋子将回归石质，世界将再无边界可言。”" },
  "332": { "n": "棋祈督", "e": 11, "r": 3, "d": "“黄金时代过去后，棋棋开始了流浪，保护族人的遗痕行为一直在影响着它们，它们会主动寻找人文聚落，试图融入洛克的社会。也有部分出现在野外，这些野生的棋棋手感不如家养棋棋温润，干巴巴的有些粗糙。”——《黄金时代的地系工匠们·八》" },
  "333": { "n": "棋绮后", "e": 11, "r": 3, "d": "“最初只有黑色棋子，后来地系工匠意外发现了光之水晶，打造了白色的棋子。黑白子交替轮班，互不相见，却共同守护地系部族。它们换班对峙时，不同棋子有各自的行走规则，逐渐发展成象棋游戏规则的雏形。”——《黄金时代的地系工匠们·四》" },
  "334": { "n": "棋骑士", "e": 11, "r": 3, "d": "“棋棋的祖先们曾与地系族人相伴而生，地系部族周围多蛮兽。白天棋棋们陷入沉睡，被当作孩子的玩具，在聚落里四处滚动。夜晚则遵循着古老的指令，纷纷醒来守护着部族，替人们守夜巡逻。”——《黄金时代的地系工匠们·三》" },
  "335": { "n": "棋齐垒", "e": 11, "r": 3, "d": "“黑白棋子们有类似铠甲一样的外形，民间传闻中白银骑士团的盔甲就是模仿它们建造的，但也有另外一种说法是地系部族的族人参与了白银骑士团的盔甲制造，真实性都已不可考。”——《黄金时代的地系工匠们·五》" },
  "336": { "n": "气球猫", "e": 13, "r": 2, "d": "外表看起来软萌，但身体其实很结实——长期保持平衡姿态，练出了稳定身体的核心肌肉。暴风雨的时候气球猫们都会紧紧抓着树或灌木，一旦松手便很可能被风吹走。" },
  "337": { "n": "牵线木偶", "e": 17, "r": 1, "d": "总是一副亲切愉悦的样子，备受小洛克们的喜欢，但似乎在没人的时候它们不会展现出一丁点生气。曾经不分昼夜持续观测一年，且让样本知道自己被观测，期间样本呈现愉悦的状态。停止观测一小时后样本所有生命体征均消失。" },
  "338": { "n": "窃光蚊", "e": 15, "r": 3, "d": "在微光沼泽，有不少因为长期触光水晶而琥珀化的精灵，这里面却没有恶名昭著的窃光蚊。这是因为窃光蚊会互相合作，一旦有个体吸收了过多光系能量，其他伙伴就会去吸收，帮助其减少体内的能量浓度。" },
  "339": { "n": "蒲公英娃娃", "e": 1, "r": 3, "d": "三个可爱的小家伙簇拥着一团轻盈的绒球，绒球的内部构造不得而知。协同发力的话，能够随心所欲地借助风力飞往任何地方。" },
  "340": { "n": "裘卡", "e": 9, "r": 3, "d": "独自活动，高傲而优雅的生物。一生中只选择一只伴侣。据研究表明裘卡的体液都有剧毒，紧张时脚垫会分泌汗液，在地面上留下有剧毒的梅花形汗渍。" },
  "341": { "n": "上岸蛙", "e": 17, "r": 3, "d": "" },
  "342": { "n": "曲率飞鱼", "e": 17, "r": 1, "d": "" },
  "343": { "n": "曲率龙卷", "e": 17, "r": 1, "d": "" },
  "344": { "n": "权杖-V", "e": 16, "r": 2, "d": "在充满斗争与冲突的时代中诞生的精灵，背负着工匠们的意志、行动与他们所点燃的第一把火。在诞生之初能向周围的机械精灵发出统一指令，它们能协调队列、分配任务，让贵族看到了机械系精灵无限的可能性。" },
  "345": { "n": "权杖-Ⅱ", "e": 16, "r": 1, "d": "黄金时代的工匠们曾将占星与炼金并列为同一门学问的两种语言。于是他们以火焰为芯，以螺纹为骨，铸成了权杖。现在只有极少量留存下来。" },
  "346": { "n": "权杖-Ⅴ", "e": 16, "r": 3, "d": "在充满斗争与冲突的时代中诞生的精灵，背负着工匠们的意志、行动与他们所点燃的第一把火。在诞生之初能向周围的机械精灵发出统一指令，它们能协调队列、分配任务，让贵族看到了机械系精灵无限的可能性。" },
  "347": { "n": "深蓝鲸", "e": 3, "r": 3, "d": "深蓝鲸们喜欢贴着水面游泳，会跳出水面，和来往船只嬉戏，遇到危险时，可以把头部冰柱发射出去。种群之间通过歌声和口哨声交流，不论距离多远，互相之间的声音都能传达到。" },
  "348": { "n": "热团团", "e": 2, "r": 1, "d": "借助风来移动的精灵，碰到水的时候会停下来休息。" },
  "349": { "n": "熔岩布丁", "e": 3, "r": 3, "d": "熔岩布丁负责增温与成熟，它体内的活性物质能促进糖分增多，在丰收季节，洛克常带着它们在可可果林区活动，帮助可可果形成更明显的甜香气味，洛克也常把它们的活跃视作可可果林健康的信号之一。" },
  "350": { "n": "燃薪虫", "e": 2, "r": 3, "d": "木头已经失去了生命迹象，没有实体的火焰精灵在死去木头的身体里栖息。往往喜欢热闹，洛克族的亲近和合作关系会让他们非常自豪。" },
  "351": { "n": "绅士鸡", "e": 2, "r": 3, "d": "充满高尚气度的种群，常把一只手放在身后。手中的羽毛可以喷射火焰，制造独特而优雅的攻击。" },
  "352": { "n": "绒仙子", "e": 4, "r": 3, "d": "完全发育成型，翅脉中内部流动着体液，横脉与纵脉交汇处形成规整的星形花纹，蕴含强烈的星光能量。胸节与携粉足极度膨大，布满致密的长绒，能牢牢黏附超多光系魔法粉末，这些粉末正是体液代谢后的产物。" },
  "353": { "n": "绒光优优", "e": 5, "r": 3, "d": "进化后它们仍然毛绒绒、行动更显优雅敏捷。战斗时旋转腾挪如轻快战舞，发光的尾巴拖出一缕光丝带。它们警惕性极高，只需将尾巴贴地，便能感知远处的动静。" },
  "354": { "n": "绒绒", "e": 4, "r": 1, "d": "绒绒多在夜间活动，触角能感知星光，体表覆盖着细密的短绒，能吸附少量蕴含星光的细微粉末。偶尔主动靠近洛克，以柔软的身体轻蹭对方，习性黏人，是温顺的小型毛绒精灵。" },
  "355": { "n": "若叶蜥", "e": 1, "r": 1, "d": "若叶蜥爱好和平，是热带雨林中的低调隐士，遇事不对便先遁走，这一习性使其练就了超强的脚力。它们在树丛间滑行，却很少有洛克可以跟随它们的脚步，分辨它们隐匿在哪片树叶下。" },
  "356": { "n": "裘力", "e": 9, "r": 2, "d": "即便在寒冷的冬天也是独来独往，从不聚在一起取暖，太冷的时候会把脚放在尾巴上。尾巴尖处有两个腺体，危险时能迅速喷射毒液，会用尾巴缠住对手释放毒素的同时使其无法逃走。" },
  "357": { "n": "裘洛", "e": 9, "r": 1, "d": "胸口的星星状器官暖烘烘的，天冷的时候裘洛们都会把前爪揣在胸口取暖。曾经有洛克贸然地接触了裘洛的尾巴，皮肤变得红肿疼痛，足足半年之后才好转痊愈。" },
  "358": { "n": "闪电小子", "e": 8, "r": 2, "d": "" },
  "359": { "n": "闪电鳗鱼", "e": 8, "r": 3, "d": "不会被自己或同类电到，那是因为电鳗体内的脂肪组织有很好的绝缘作用。几乎全身的肌肉组织都能放电，其生物电能与闪电产生强烈共鸣，某些个体能够定向引雷、身体所能承受的电能最高可达8600000伏。" },
  "360": { "n": "嗜光嗡嗡", "e": 15, "r": 1, "d": "“经实验发现，它们对日光没有反应，其腹部含有特殊的器官，只对光系能量产生反应。因此，存放光水晶时需派遣光系精灵巡逻，混淆它们的感应。”“光系精灵一同发出抗议，要求王国打击嗜光嗡嗡的狂热跟踪和过分亲近行为。”" },
  "361": { "n": "嗜波螺", "e": 5, "r": 3, "d": "在海浪冲击下，演化出坚韧的矿物质石柱外壳，是一种非常稳定的消波结构，能把浪涌的力量层层化解。声音在石柱间隙中不断反射产生共鸣，能发出类似海浪的声音。" },
  "362": { "n": "噬影蚕", "e": 14, "r": 1, "d": "" },
  "363": { "n": "圣代甜甜", "e": 6, "r": 3, "d": "喜欢群居的团结者，圣代甜甜诞生时就生有两颗冰淇淋球，相生相伴，两颗冰淇淋球口味性格不同却能一直融洽相处。" },
  "364": { "n": "圣光迪莫", "e": 4, "r": 2, "d": "身体中蕴含着光之魔法的力量。有着光一般的勇气，无论什么情况下都会守护同伴。" },
  "365": { "n": "圣凯布米龙", "e": 2, "r": 1, "d": "借助风来移动的精灵，碰到水的时候会停下来休息。" },
  "366": { "n": "圣剑-X", "e": 16, "r": 3, "d": "制造者把牺牲和奉献作为圣剑的使命，接下来它的一切行为都是为了实现这个目的，无数十号圣剑就这样留在了从前的时代里。现在黄金时代的风早已停息，暗夜过后也迎来了新生。" },
  "367": { "n": "圣剑侍从", "e": 16, "r": 1, "d": "黄金时代的工匠们曾将占星与炼金并列为同一门学问的两种语言。于是他们以风为芯，以力量和律法为骨，铸成了圣剑。现在只有极少量留存下来。" },
  "368": { "n": "圣剑骑士", "e": 16, "r": 3, "d": "永远不会停下的机械，被发现的时候伤痕累累，曾经被修复过很多次，修复后的身体仍然能发出超过5000度的光焰。其身体内部刻着古代文字意为：熄灭不是终结，等待新生到来，它将重铸工匠的意志。" },
  "369": { "n": "圣水守护", "e": 3, "r": 3, "d": "“无论是云中落下的一滴水，还是湖面中微风吹起的一道涟漪，都有她的身影。”" },
  "370": { "n": "圣羽翼王", "e": 12, "r": 3, "d": "庇佑这片纯粹的净土，是拥有强大力量之后背负的使命。从上古壁画中得知尘封的过往，它寻求力量，发自内心地想要保护现在的一切。“张开圣洁的羽翼，为同伴抵挡风雨，便是它心中的圣歌”。" },
  "371": { "n": "圣草迪莫", "e": 4, "r": 2, "d": "身体中蕴含着草之魔法的力量。" },
  "372": { "n": "声波缇塔", "e": 16, "r": 3, "d": "长长的机械触手可以更方便地抓取物品，遵守着古老的机器守则，然而其需要寻找的物品，似乎早已消逝在历史中。“更加强大的功能，见到机械，它们会毫不留情地抓过来。见到洛克，也会毫不留情地抓过来。”" },
  "373": { "n": "深渊蛙", "e": 3, "r": 1, "d": "" },
  "374": { "n": "石冠王蜥", "e": 5, "r": 3, "d": "普遍性情暴躁，攻击性强，会发射岩石来划清自己的地盘。它背上石头与身体融合的原理至今仍是研究协会重要的研究课题。" },
  "375": { "n": "石刺蜥", "e": 5, "r": 2, "d": "背上的石头似乎会与身上的棘刺融为一体，成为自己的武器。石头会周期性脱落，脱落下来的石头苍白易碎，捏一下就会粉碎成细砂状。" },
  "376": { "n": "神谕鲨", "e": 3, "r": 3, "d": "暴雨时，它将雨水储藏在身体中；干旱降至，它在半空挥舞翼膜，水分升空化作雾墙，再聚成雨云。“这一路上，跌跌撞撞，有时快乐，有时候感伤，可是它依然坚强，哪怕真的没有尽头，它都愿意继续前行。”" },
  "377": { "n": "食尘短绒", "e": 10, "r": 3, "d": "绒毛短而浓密，出没在灰尘多的地方，能够在任何表面爬行，其脚掌上短且蓬松的绒毛在爬行时会产生静电作用，牢牢地黏在物体表面上，吸附灰尘，清理家具的死角。" },
  "378": { "n": "书卷守护", "e": 0, "r": 2, "d": "身上带着书本和油墨的味道，看起来小小的，其实比想象中重很多。常与同伴交换藏书，偶尔遇到疑惑的地方，会用书使劲砸自己的头，希望用这种办法让知识快点进入身体。" },
  "379": { "n": "书魔虫", "e": 0, "r": 1, "d": "沉迷于阅读，其力量来源于书本的知识。走路和睡觉时都手不释卷，读的书越多体型变得越大，隔一段时间就要调整绑书带的长度，不然会阻碍它学习新知识。" },
  "380": { "n": "十字蛙", "e": 3, "r": 2, "d": "" },
  "381": { "n": "十字蝌蚪", "e": 3, "r": 1, "d": "" },
  "382": { "n": "双灯鱼", "e": 3, "r": 1, "d": "头顶的光似乎并不是光系魔法，而是来自于某种寄生在其身上的会发光的细菌，目前不清楚发光细菌的其他特性，即使在水中也必须把头顶的灯伸到水面上。" },
  "383": { "n": "帅帅魔偶", "e": 17, "r": 2, "d": "非常偶然的情况下发现它们殴打自己身上闪烁着的微光的提线。提线中流动着强大魔力，以此来操纵结构精巧的木质结构身体，看似十分脆弱，但在幻系魔力的支撑下，有着令人意想不到的破坏力。" },
  "384": { "n": "朔夜伊芙", "e": 15, "r": 3, "d": "喜欢在远处观察其他精灵的活动，有时会故意制造幻象来测试目标的反应。几乎不与同类接触，有些排斥社交，意外的是，被亲近的洛克抚摸的话耳朵尖会发光。" },
  "385": { "n": "松仔", "e": 1, "r": 1, "d": "如果察觉到小洛克踏入森林，它们会把角塞在树杈中间伪装松果，诱使小洛克靠近观察。被林间露水打湿的话它们会结伴去晒太阳，晒太阳的时候会散发香香的味道。" },
  "386": { "n": "松叶羊", "e": 1, "r": 2, "d": "刚刚经历换角，松果模样的角脱落，身上的针叶变得锋利，逐渐觉醒领地意识。换角的过程中不要贸然靠近，不然会被踢出几米远。被踢的时候可以闻到它们身上带着森林中泥土和青草的香味。" },
  "387": { "n": "水泡壳", "e": 3, "r": 3, "d": "进化之后体重增长到原来的三倍多，前肢的力量也变得十分发达。前面有坚硬的尖角，背后有甲壳和水炮的泵口，是像堡垒一样可靠的存在。" },
  "388": { "n": "水滴蛇", "e": 3, "r": 1, "d": "和水滴蛇对上眼神的时候，最好保持礼貌并且尝试解答它们留下的难题，如果拒绝回答或敷衍，往往会招来恶作剧，让你在不知不觉中迷路或错过冒险的宝藏。" },
  "389": { "n": "水灵", "e": 3, "r": 3, "d": "将刚刚孕育的胚胎顶在头上，胚胎由特殊水元素包裹着。能将身边的水元素汇集在一起喷射出去，产生强大的冲击力。“无论是云中落下的一滴水，还是湖面中微风吹起的一道涟漪，都有她的身影”。" },
  "390": { "n": "水蓝蓝", "e": 3, "r": 1, "d": "漂浮在水面上的精灵，没事吐个泡泡，头顶有一个红色的蝴蝶结。不在水中的时候，身体上也覆盖了一层液体薄膜。" },
  "391": { "n": "水蛇锁", "e": 3, "r": 2, "d": "水蛇锁经常悄悄靠近洛克，没有半点声响。它们不以贪婪著称，也不说谎。它们的目的是汲取你的知识。试试用最珍贵的知识与它交换，或许就能平安离开。" },
  "392": { "n": "溯源钟", "e": 16, "r": 2, "d": "飞起来时摇摇晃晃的，翅膀会发出”嘎吱“声，像是旧手工造物，实际拥有少量扭转时间的能量，会边发出”布谷“的声音，边从嘴里弹出时间炸弹，炸弹一旦爆炸，会短暂扭曲周围的小范围时间，让追逐者的动作变迟缓。" },
  "393": { "n": "贪食鼹", "e": 0, "r": 2, "d": "吻部变得坚硬，形状如同吸管，舌头又长又黏。没有嗅觉器官，通过舌头来感知气味，经常舔舐各种味道刺激的东西。" },
  "394": { "n": "速粒冲锋", "e": 15, "r": 2, "d": "" },
  "395": { "n": "速粒小子", "e": 15, "r": 1, "d": "" },
  "396": { "n": "霜翼领主", "e": 12, "r": 3, "d": "传说霜翼领主会在冬季的末尾巡视领地，当它最后一次掠过雪线，天空便不再下雪——所有雪花都被它收进了冰蓝色的羽翼。只需一次振翅，零下五十度的寒潮便顺着羽脉倾泻，瞬间把战场变成镜面。" },
  "397": { "n": "乌咩", "e": 13, "r": 1, "d": "" },
  "398": { "n": "乌角驮驮", "e": 13, "r": 2, "d": "" },
  "399": { "n": "小光", "e": 15, "r": 1, "d": "" },
  "400": { "n": "小灵菇", "e": 14, "r": 1, "d": "可能在任何潮湿的阴冷角落出现，看到蓝色荧光不要贸然接近。吸食其他生物的情绪作为养分，吃饱后会发出轻轻的叹气声。" },
  "401": { "n": "小螂", "e": 10, "r": 1, "d": "身体十分柔软，经常挥舞着还未发育完全的前肢。似乎还没有视觉。靠头顶的触角收集周围信息，如果触角受伤了，会完全迷失方向。" },
  "402": { "n": "武斗酷猫", "e": 1, "r": 1, "d": "" },
  "403": { "n": "武者鸡", "e": 2, "r": 3, "d": "极其发达健壮的双臂是它们的标志性特征，手部演变为锋利的钙化物质。这一分支舍弃了种族遗传下来的火焰魔法，堂堂正正地用双手和踢腿打败敌人。" },
  "404": { "n": "消波螺", "e": 5, "r": 2, "d": "进化后，外壳生长速度更快，更需要精心维护——它们会定期在岩石上打磨外壳。个体之间还会互相叠在一起摩擦打磨，发出“砰砰”的声响。若较长时间没有打磨，行动会明显变慢。" },
  "405": { "n": "犀角鸟", "e": 4, "r": 1, "d": "足部又软又嫩，相当虚弱无力。双眼的视觉暂未发育完全，偶尔被毛发遮挡视野。研究推测其毛发承担了主要感官的功能，在看不清的时候也可以通过毛发的感光功能，早早隐藏好自己。" },
  "406": { "n": "缇塔", "e": 16, "r": 1, "d": "总是扫描寻找着什么，明明对洛克抱有极大的好奇，但是因为其机器守则限制，只能和洛克保持在一个不远不近的距离。“既可靠又实用，深得洛克们青睐，是您寻物时的不二之选。”" },
  "407": { "n": "舞动路路", "e": 1, "r": 2, "d": "每只舞动路路都携带着一颗蛋，经常看到它们用头上的毛发擦拭蛋，那是它们最珍视的一部分。蓬松的毛发下看不到眼睛，主要靠头上的叶片来感受环境，身体非常灵活。" },
  "408": { "n": "香草甜甜", "e": 6, "r": 2, "d": "香草甜甜一族口感各有不同，头上顶着的果果是身体的一部分，拥有360度的视野。因果果吸收不同能量而演化出不同口感分支，身体散发着浓郁的奶香。" },
  "409": { "n": "小冥龙", "e": 14, "r": 1, "d": "" },
  "410": { "n": "小勇狮", "e": 2, "r": 1, "d": "喉咙处有容纳火系魔法的身体结构，在小勇狮身上还不太明显，偶尔能发现它打喷嚏的时候会喷出小火花。" },
  "411": { "n": "小帕尔", "e": 15, "r": 1, "d": "探索欲很强的精灵，会通过摇尾巴的方式表达亲近，尾尖会散发出魔法，但并不能很好地控制，时常伤到自己。" },
  "412": { "n": "小皮球", "e": 8, "r": 3, "d": "浑身散发着紫色的微光，有时会在夜晚拿出珍藏的星星，为迷途的旅人照亮归途。得益于柔软的身体结构，能够将不稳定的星光能量储存在体内，据说星星的亮度代表着存储能量的强度。" },
  "413": { "n": "小绒茧", "e": 4, "r": 2, "d": "体表的短绒进化为蓬松且带有黏性的长绒，能够吸附并储存更多星光粉末，直接触摸的话，会感到轻微刺痛。它们吸附的粉末最终在体内融合，驱动体内组织发生解离和重塑，当能量饱和时，绒毛能爆发出强劲的冲击力。" },
  "414": { "n": "小翼龙", "e": 7, "r": 1, "d": "身形圆润可爱，翼膜十分柔软，只能在陆地上漂浮。植食性，最爱啃蕨类于低矮灌木，进食的时候总是呛到，猜测是因为呼吸系统还没有发育完全，需要用嘴巴呼吸。" },
  "415": { "n": "小银翼龙", "e": 16, "r": 1, "d": "" },
  "416": { "n": "星云旅者", "e": 12, "r": 3, "d": "孤独又神秘的旅者，似乎是天外来客，不知道它来自何方，又要去往何处。喜欢对着天空冥想，似乎是在寻找回家的路，又或是思索着星辰间的秘密。它只是伴随着星光，继续向未知的远方迈进。" },
  "417": { "n": "星尘虫", "e": 10, "r": 1, "d": "洛克与精灵开始缔结契约的时候诞生的物种。以精灵契约为食，是极其稀少的物种。囫囵吞下咕噜球后，先整个保存在身体里一段时间，非常久之后才能完全消化掉。虽然也能吃其他食物，但很难从中获取养分。" },
  "418": { "n": "邪眼巨魔", "e": 15, "r": 1, "d": "十分谨慎的种族，甚至睡眠时间极短，常处于高度紧张的戒备状态。通过观测发现额头上第三只眼中储存着大量能量，目前发现眼中能量溢出的现象在其睡觉的时候尤为明显。" },
  "419": { "n": "雪巨人", "e": 6, "r": 3, "d": "雪巨人感官极其敏锐，能感受到天气和气温的微小变化，会在族群的幼崽沉睡时巡逻保护它们。双臂能够撑地进行超远距离跳跃，在雪山里飞速前进，跳跃时在岩石上留下后足形状。" },
  "420": { "n": "雪灵", "e": 6, "r": 3, "d": "只有当契约者死亡的时候才会寻找下一位契约者。假如原契约者活着，但它们必须更换契约者的话，可能会自我了结生命。" },
  "421": { "n": "雪灵兽", "e": 6, "r": 1, "d": "" },
  "422": { "n": "雪顶布鲁斯", "e": 6, "r": 2, "d": "晶体化结构更稳定，修长的腕足变得更灵活，能细致地打理身体、调整伪装姿态，白色绒球对温差的感知也更敏锐。" },
  "423": { "n": "叶冕魔力猫", "e": 1, "r": 3, "d": "“每天尽情地吃可可果，和喜欢的小洛克一起冒险，是很开心的生活。”" },
  "424": { "n": "夜宿颅", "e": 14, "r": 2, "d": "吓退其他精灵以取乐，有人说他们以恐惧为食，但没人考证过真假。看起来像眼睛的部分并没有视觉神经，实际通过感知热量来代替视觉。" },
  "425": { "n": "学院呱呱", "e": 11, "r": 1, "d": "心中怀揣着对魔法的强烈渴望和对广阔知识世界的向往，呱呱从玄玉岛来到魔法学院。咒语对它们来说就像绕口令，因此需要花费更多的时间来学习，在魔法学院的走廊，经常能看到它们带着歪歪扭扭的自学笔记飞奔的身影。" },
  "426": { "n": "曜星光", "e": 17, "r": 2, "d": "越来越多的行星汇聚在它们身侧，从星辰的辐照微波中，它们能横跨时间，读出数亿年的知识与奥妙。每当它们转动身体周围的行星，可以改变月相，转变天气，传闻如果有洛克在它们出没的高山附近许愿下流星雨，就会被实现。" },
  "427": { "n": "椰浆布丁", "e": 3, "r": 3, "d": "椰浆布丁负责降温与保鲜，它能在体表形成一层很薄的冷凝膜，使自身在温暖环境中不易软化变形。它常出现在有人维护的洁净水源附近，并更愿意与洛克共存，阴凉的室内能提高它们的舒适度。" },
  "428": { "n": "焰火", "e": 2, "r": 2, "d": "长出了一对大翅膀，但似乎并不是用来飞行的。能用双手释放出更加强力的火焰，但不太熟练。" },
  "429": { "n": "焰米龙", "e": 2, "r": 1, "d": "借助风来移动的精灵，碰到水的时候会停下来休息。" },
  "430": { "n": "燕尾獭", "e": 0, "r": 2, "d": "牙齿锋利，非常喜欢啃一些坚硬的木头。手掌心非常坚硬粗糙，常看到它们用手在脸上搓来搓去，并不是在洗脸，而是在用掌心磨牙齿。" },
  "431": { "n": "芽眼魔", "e": 15, "r": 1, "d": "总是没精打采的，睡着的时候会用头顶的芽芽盖住眼睛。通过头顶的芽感受和接收外界一切信息。即使本体处于睡眠状态的时候，头顶的芽也能警戒危险。" },
  "432": { "n": "雅丹鬃", "e": 2, "r": 3, "d": "岁首更替，丙午是天地通明的光明之年，传闻雅丹鬃是光明的使者，会在新年的子夜仰首长嘶，声如裂帛，鬃毛化作飞天的流火长带，照得千里沙海通明。此时，万盏红灯同时亮起，仿佛回应烈马奔腾——天地通明，光明永昼。" },
  "433": { "n": "雪影冰灵", "e": 6, "r": 3, "d": "如果遇到了致命的危险，毛绒娃娃会变成巨大的兔精灵来保护主人。不要贸然靠近，不然它会非常生气。这时的它有明确的领地范围，喜欢用耳朵的香腺擦拭东西来划分地盘。如果它用耳朵蹭蹭你，代表你可以接近。" },
  "434": { "n": "雪影娃娃", "e": 6, "r": 3, "d": "进化后头部绒毛完全脱落，褪去的绒毛承载着进化前的回忆，被制作成一个毛绒娃娃。毛绒娃娃如果能抵御一个严冬就可以获得生命，过程中需要雪影娃娃的悉心养护。" },
  "435": { "n": "雪绒鸟", "e": 12, "r": 1, "d": "冬天诞生的小鸟精灵，常把身体缩成球状减少散热。喜欢用幼嫩的喙啄刚落地的新雪，既是食用也是玩耍。" },
  "436": { "n": "雪蛮人", "e": 6, "r": 2, "d": "上肢沉重却灵活，体表鬃毛格外厚重，兼具保暖与防护的功能。吸收的寒气能够压缩后储存在脊背和额头上，形成坚实有力的冰晶，用以保持平衡和击打对手。" },
  "437": { "n": "鸭吉吉国王", "e": 0, "r": 3, "d": "啪嗒啪嗒，鸭吉吉国王来了。那边的，别看怀表了，让时间听国王的；这边的毛太蓬松了，站紧实一点，别挡着国王的道了。嗯？还有你，既然来了我们鸭吉吉王国，记得要给过路费鸭！" },
  "438": { "n": "仪使者", "e": 5, "r": 1, "d": "在很久很久前被洛克族在遗迹的深处发现，可能已经有上千年的历史了。它的身体由宝石和贵重的金属组成，是被追求财富的人争抢的对象。" },
  "439": { "n": "仪式之星", "e": 5, "r": 2, "d": "曾被误认为是雕像，但却有意识和情绪。传说它的身体上镶嵌的宝石象征三种元素。被认为是完美平衡的象征，有研究证明它能够感知或预测时间的流动。" },
  "440": { "n": "仪式巨像", "e": 5, "r": 3, "d": "经过时间的洗礼，有些残缺的痕迹，是谜一般的存在，与其相关的研究记录十分少。但相反的这个种族似乎对洛克族十分了解和亲近。“也许生命会消失，从人们的记忆中淡忘，但文明的传承不会断绝。”" },
  "441": { "n": "伊丽莎白", "e": 2, "r": 1, "d": "将翅膀作为武器，被它攻击过的地方都会留下火焰燎烤的痕迹，但同时也会烤焦自己。在进食过急或精神紧张的的情况下比较容易消化不良，身体的分泌物也是易燃物。" },
  "442": { "n": "伊兰亚龙", "e": 7, "r": 3, "d": "当它舒展躯体时，水流沿鳞片纹路均匀铺展，使其外形兼具威慑力与神圣感，威严而不可侵犯。“在龙系精灵的历史中起到了关键的作用，一直默默地付出，很少有人知道它的存在。”" },
  "443": { "n": "伊兰龙", "e": 7, "r": 3, "d": "修长的尾鳍在空气中划过会留下水雾的痕迹，水雾持续存在形成云朵。观测显示，伊兰亚龙停留超过半小时的区域，降雨概率提升67%。干旱季节时，它们会主动迁往缺水的农田上空。" },
  "444": { "n": "伊贝儿", "e": 1, "r": 1, "d": "它头顶长着一团蓬松的绿色苔藓，压低身体时能很好地融入草丛，几乎难以分辨。苔藓本身不疏水，一旦沾到水就会迅速吸收并变得沉重，让它行动迟缓甚至走不动，只能停在原地等待自然风干。它的身体像果冻一样具有弹性，可拉伸变形。" },
  "445": { "n": "伊贝粉粉", "e": 1, "r": 3, "d": "苔藓常把眼睛遮住，因此它对细微动作的反应显得迟钝。若有洛克替它把苔藓梳理开，它会明显变得开心。进食后体型会短暂膨大一圈，随后再慢慢恢复原状。" },
  "446": { "n": "叶眼魔", "e": 15, "r": 2, "d": "喜欢用恶系能量恶作剧，常常在探险的小洛克面前立一道空气墙，看洛克们撞得晕头转向。头顶的叶片中蕴含着强大的恶系能量，释放能量时，叶片会缓缓燃尽，需要很长一段时间才能恢复为完整的叶片。" },
  "447": { "n": "夜枭", "e": 14, "r": 3, "d": "充盈着魔力的巨爪十分有力。曾经被夜枭吞下过的生命，虽然躯体看似无碍，灵魂却缺失了一部分。" },
  "448": { "n": "夜游魔", "e": 12, "r": 1, "d": "" },
  "449": { "n": "幽星光", "e": 17, "r": 1, "d": "夜幕的星光之下，这些奇妙的生灵在观测星空，思考并记录时会发出像唱歌一样的声音。它们就像在歌唱宇宙，赞颂复苏，诉说星河的曼妙与知识的无常。但是非常胆小，每当其他生物出现，它们又会隐身于夜空中。" },
  "450": { "n": "影狸", "e": 14, "r": 3, "d": "总是弓着身子，脊椎特化为毒刺弹射装置，用来发射尾巴上的尖刺。体内另外储存了几十根可再生的空心毒刺，通过弹射加压能以每秒10发的速度喷射。" },
  "451": { "n": "游蛇魔使", "e": 3, "r": 3, "d": "会被聪明的洛克吸引，对知识的崇拜无以复加，愿意用任何自己所拥有的事物来交换知识。它们拥有修长柔软的尾巴，据说尾巴尖端可以打开远古的知识之门。" },
  "452": { "n": "翼龙", "e": 7, "r": 3, "d": "拥有庞大的身躯，肚子总是鼓鼓的，充满发酵的食物。它有力的双翼和坚韧的躯体仿佛为长途飞行而生，在疾飞时仍能自由呼吸。" },
  "453": { "n": "银翼龙", "e": 16, "r": 2, "d": "" },
  "454": { "n": "音速犬", "e": 2, "r": 3, "d": "昂起斗志时，冠毛和尾巴会像熊熊燃烧的火焰一样摇曳。身上的围巾蕴含魔法能量，似乎有增强火元素的效果。" },
  "455": { "n": "饮雪狂兽", "e": 6, "r": 1, "d": "" },
  "456": { "n": "圆号鱼", "e": 3, "r": 3, "d": "会专门去矿物质丰富的水域，通过吸收矿物质来调整背部结构，达到调音的目的。群居，每天早上起来一齐练声，巨大的合奏声能唤醒周围水域的所有生物，喜欢安静的精灵们不愿意住在它们旁边。" },
  "457": { "n": "圆眼蜘蛛", "e": 10, "r": 1, "d": "幼体的圆眼蜘蛛并不太能织网捕食，多以青草，树果为食。复眼获取信息范围极大，速度极快，即便是独眼，圆眼蜘蛛获取信息速度远超过洛克族100倍。" },
  "458": { "n": "增肌猫", "e": 11, "r": 2, "d": "学习了名为“无氧法术”的迷之魔法，身形也因为练习“无氧法术”而发生了变化。崇尚质朴的力量，即便学习“无氧法术”，也是为了通过魔法来提升自己的武力。" },
  "459": { "n": "晕晕鸡", "e": 2, "r": 2, "d": "成长后学会了控制情绪，维持着绅士风度，为了追求优雅和游刃有余，逐渐更能控制火焰释放。偶尔会因为忍耐过度，大脑变得晕乎乎的。" },
  "460": { "n": "月牙雪熊", "e": 6, "r": 3, "d": "额前的星星质地不明，触感温热，能够从其中检测到异常的魔力波动。如果星星离开身体太远的话，身体会进入沉睡状态。“虽然它从不去看，但是魔法丢得很准。”" },
  "461": { "n": "秩序鱿墨", "e": 14, "r": 3, "d": "身体覆上整齐的黑白方格，触手末端变成细长的金属尺，能把漂浮的墨滴精确切割成等分方块。它从不越界，乐于将墨汁按深浅、冷暖、浓度排成矩阵，精准而冷静。" },
  "462": { "n": "紫夜", "e": 15, "r": 2, "d": "经常四处游历，偶尔幻化成其他精灵的样子之后偷偷潜入其他族群中，猜测是为了锻炼自己的幻化能力。通常情况下喜欢独自生活。" },
  "463": { "n": "紫翎鹰", "e": 12, "r": 2, "d": "" },
  "464": { "n": "紫蔓宝宝", "e": 1, "r": 1, "d": "极其罕见的精灵，最早洛克们似乎把这种精灵误认为是幼鹿。身体周围的藤曼每天黄昏都会脱落枯萎，再长出新芽。" },
  "465": { "n": "紫蔓祭祀", "e": 1, "r": 2, "d": "对陌生人敌意极大，极难接近。从藤曼触手中散发能量，令枯萎的树木发芽。" },
  "466": { "n": "芋香巨角蛛", "e": 10, "r": 3, "d": "颜色鲜艳美丽，尾部丝囊中的液体有剧毒，织出的蜘蛛网散发异香。依靠体毒和利刺能轻易捕获猎物，从不群居，个体之间都保持一定距离，互不侵犯。" },
  "467": { "n": "针叶巡林", "e": 1, "r": 3, "d": "角上覆盖的鳞片脱水后自然开裂成树枝状，在森林中极其灵活地穿梭，极少被洛克持续观测到。它们拥有修长的身体和轻盈的骨骼结构，奔跑迅速。" },
  "468": { "n": "钻地小子", "e": 8, "r": 1, "d": "" },
  "469": { "n": "长尾火鸟", "e": 2, "r": 2, "d": "尾巴上有一对弯月状的羽毛，仿佛是地位的象征。头上的钻石如果受到刺激会爆发出强烈的火焰。" },
  "470": { "n": "陨星虫", "e": 10, "r": 3, "d": "在这个虫族中存在着森严的等级制度，某些虫有资格吃到更稀有的咕噜球。咕噜球研究科曾经提出过一个实验课题《陨星虫与国王球的对撞实验》，后来课题被取消了，原因不明。" },
  "471": { "n": "障眼魔", "e": 15, "r": 1, "d": "" },
  "472": { "n": "钻石蜗", "e": 4, "r": 3, "d": "极其稀少且强大的精灵，见到它时，洛克的第一反应不是抓起来，而是先停手——它的壳太硬，硬到任何挖掘工具碰到它都会立刻坏掉。凡是矿区附近有钻石蜗出现，都需要先报告给魔法学院的研究员。" },
};
